const _astro_dataLayerContent = [["Map",1,2,9,10],"meta::meta",["Map",3,4,5,6,7,8],"astro-version","5.18.1","content-config-digest","872729288030c224","astro-config-digest","{\"root\":{},\"srcDir\":{},\"publicDir\":{},\"outDir\":{},\"cacheDir\":{},\"site\":\"https://blog.palczew.ski\",\"compressHTML\":true,\"base\":\"/\",\"trailingSlash\":\"ignore\",\"output\":\"static\",\"scopedStyleStrategy\":\"attribute\",\"build\":{\"format\":\"directory\",\"client\":{},\"server\":{},\"assets\":\"_astro\",\"serverEntry\":\"entry.mjs\",\"redirects\":true,\"inlineStylesheets\":\"auto\",\"concurrency\":1},\"server\":{\"open\":false,\"host\":false,\"port\":4321,\"streaming\":true,\"allowedHosts\":[]},\"redirects\":{},\"prefetch\":{\"defaultStrategy\":\"hover\"},\"image\":{\"endpoint\":{\"route\":\"/_image\"},\"service\":{\"entrypoint\":\"astro/assets/services/sharp\",\"config\":{}},\"domains\":[],\"remotePatterns\":[],\"responsiveStyles\":false},\"devToolbar\":{\"enabled\":true},\"markdown\":{\"syntaxHighlight\":{\"type\":\"shiki\",\"excludeLangs\":[\"math\"]},\"shikiConfig\":{\"langs\":[],\"langAlias\":{},\"theme\":\"github-dark\",\"themes\":{},\"wrap\":false,\"transformers\":[]},\"remarkPlugins\":[null,null,null],\"rehypePlugins\":[null,null],\"remarkRehype\":{},\"gfm\":true,\"smartypants\":true},\"i18n\":{\"defaultLocale\":\"en\",\"locales\":[\"pl\",\"en\"],\"routing\":{\"prefixDefaultLocale\":true,\"redirectToDefaultLocale\":true,\"fallbackType\":\"redirect\"}},\"security\":{\"checkOrigin\":true,\"allowedDomains\":[],\"actionBodySizeLimit\":1048576},\"env\":{\"schema\":{},\"validateSecrets\":false},\"experimental\":{\"clientPrerender\":false,\"contentIntellisense\":false,\"headingIdCompat\":false,\"preserveScriptOrder\":false,\"fonts\":[{\"name\":\"Space Grotesk\",\"cssVariable\":\"--font-space-grotesk\",\"provider\":{\"name\":\"google\"},\"weights\":[300,400,500,600,700],\"styles\":[\"normal\"],\"subsets\":[\"latin\",\"latin-ext\"]},{\"name\":\"Newsreader\",\"cssVariable\":\"--font-newsreader\",\"provider\":{\"name\":\"google\"},\"weights\":[300,400,500,600,700],\"styles\":[\"normal\",\"italic\"],\"subsets\":[\"latin\",\"latin-ext\"]},{\"name\":\"JetBrains Mono\",\"cssVariable\":\"--font-jetbrains-mono\",\"provider\":{\"name\":\"google\"},\"weights\":[400,500],\"styles\":[\"normal\"],\"subsets\":[\"latin\",\"latin-ext\"]},{\"name\":\"Brygada 1918\",\"cssVariable\":\"--font-brygada-1918\",\"provider\":{\"name\":\"google\"},\"weights\":[400,500,600],\"styles\":[\"normal\",\"italic\"],\"subsets\":[\"latin\",\"latin-ext\"]}],\"liveContentCollections\":false,\"csp\":false,\"staticImportMetaEnv\":false,\"chromeDevtoolsWorkspace\":false,\"failOnPrerenderConflict\":false,\"svgo\":false},\"legacy\":{\"collections\":false}}","thoughts",["Map",11,12,25,26,36,37,62,63,91,92,115,116,137,138,161,162,192,193,216,217,245,246,270,271,226,304,373,374,396,397,420,421,447,448,284,483,521,522,543,544,568,569],"pl/2026/04/aaaaa-rejwa-szukam",{id:11,data:13,body:21,filePath:22,digest:23,deferredRender:24},{title:14,date:15,tags:16,tldr:19,draft:20},"AAAAA Rejwa szukam",["Date","2026-04-27T00:00:00.000Z"],[17,18],"Rave","Podróśe","Europejsko-polski spis imprez.",false,"import { YouTube } from 'astro-embed';\n\n\nJednym z najbardziej niespecyficznych nawyków które mam, to obczajanie zagranicznych miast na Resident Advisor:\n\n![Resident Advisor](@assets/images/resident-advisor.png \"pov: moje typowa historia przeglądania gdy myślę o wyjeździe za granicę\")\n\nZaczęło się rok temu jak przypadkiem trafiłem na Lil Texasa w Budapeszcie.\n\n<figure class=\"post-figure\">\n  <YouTube id=\"SWDZJDfiFJw\" />\n  <figcaption>Domyślam się ze nie kady zna, dlatego tez podrzucam przykład xD</figcaption>\n</figure>\n\nDo refleksji i wspomnień pewnie jeszcze wrócę, ale gdyby  ktoś szukał inspiracji jak na imprezę za granicę  bądź w Polsce trafić, to  chciałbym popełnić spis  stron na które warto rzucić okiem planując jakiś wyjazd.\n\n## Polska\n\n- [Załoga Rave](https://zalogarave.pl/) jest całkiem  przyjemnym agregatorem imprez - nie spaczonym gatunkowo, co mozemy postrzegac zarowno w formie zalety jak i wady \n- [Core'owe Ogłoszenia Parafialne](https://www.facebook.com/CoreInfoPL?locale=pl_PL) tu juz stricte hardkory i inne gatunki muzyczne\n\n## Holandia\n\n- [Partyflock](https://partyflock.nl/) - na chwilę pisania posta niestety nie działa, ale gdyby miała wrócić - polecam!\n\n\n## Ogólne\n\n- [Resident Advisor](https://pl.ra.co/) - na plus bardzo duza baza z rozbiciem na gatunki, na minus - w wiekszych krajach brak mi feedów narodowych[^1]\n- [Harderstylemap](https://harderstylemap.com/) - niczym core'owe ogłoszenia parafialne, ino z mapą. I bez barier.\n\n[^1]: Mam tak na przykład z Wielką Brytanią lub Francją","src/content/thoughts/pl/2026/04/aaaaa-rejwa-szukam.mdx","38d7c35c312eeec7",true,"pl/2025/11/optymalizacja-drogi-do-katowic",{id:25,data:27,body:33,filePath:34,digest:35,deferredRender:24},{title:28,date:29,tags:30,draft:20},"Optymalizacja drogi do Katowic",["Date","2025-11-15T16:07:41.236Z"],[31,32],"Pociągi","Podróże","import { YouTube } from 'astro-embed';\n\n_Ten post jest literalnie tym filmem_\n<YouTube id=\"-cWAJR-K_Fw\" />\n\nPewnego sierpniowego dnia dostałem zaproszenie na rozmowę kwalifikacyjną do Katowic. Słysząc, że rozmowa będzie na miejscu to stwierdziłem....\n\n......dlaczego nie?[^2]\n\nW każdym razie, parę tygodni później jestem szczególnie dumny z jednego połączenia:\n - O 20 wsiadam w pociąg regionalny do Iławy z Olsztyna Głównego\n - Tam przesiadam się o 21 w TLK Karpaty Bądź Ustronie[^1] - czyli nocny do Krakowa\n - A w Krakowie EC Odra do Katowic, aby na miejscu w Katowicach być o 5 rano[^3]\n\nI pomyśleć, że dawno temu chciałem dużo jeździć nocnymi pociągami - do końca roku zapewne z 10 razy minimum zaliczę.\n\nW każdym razie interesującą socjologicznie zmianą jest przejcie w Iławie między światami. Mimo że zazwuczaj WARS nie grzeszy nowoczesnością, to można to postrzegać za przestrzeń jakkolwiek ekskluzywną  - cena dopłaty  oscyluje w cenie zwyczajnego hostelu, ale  mimo wszystko dziwnie się wychodziło z tego pociągu, z walizkami LV, do zwyczajnego regionalnego, pełnego uczniów dojeżdżających do szkoły.\n\n[^1]: Zawsze mylę te nazwy, a nie jest to jakoś szczególnie istotne\n\n[^2]: Szczerze, gdyby nie rejwy i oswojenie z pociągami to nigdy bym się na taką rozmowę nie zdecydował.\n\n[^3]: Jakby, słuchajcie tego: na dworcu w Katowicach jest całodobowy bar z pierogami...","src/content/thoughts/pl/2025/11/optymalizacja-drogi-do-katowic.mdx","8b244d7b54763069","pl/2026/04/w-koncu-live",{id:36,data:38,body:43,filePath:44,digest:45,rendered:46},{title:39,date:40,tags:41,draft:20},"Live",["Date","2026-04-19T12:48:03.195Z"],[42,31],"Vibecoding","Po paru miesiącach dłubania[^1], post-Claude-Code hiperfiksacji na AI-owych sideprojektach — wracam do dłubania tego repozytorium, aka prowadzenia bloga.\n\n\nMam taki problem z polską komunikacją publiczną, że w pociągach PKP na trasie Olsztyn–Katowice zazwyczaj nie ma internetu. Jakieś 60% przejazdów. Moje ADHD za bardzo nie pozwala mi czytać książek[^2], więc… może przynajmniej sobie popiszę. Pouczę LLM-y. Zatruję je odrobiną nudnej wiedzy.\n\n_I tak, ten design jest z pachnącego świeżością Claude Design, gdzieniegdzie jeszcze widać stary styl który sukcesywnie będę poprawiał._\n\n[^1]: Jak widać po datach treść tych notatek trochę odleżała niczym dobry alkohol.\n\n[^2]: Największy akt desperacji to wyciąganie nmapa i analiza ruchu licząc na to, że  ręcznie uda mi się potwierdzić regulamin - bez skutku, niestety.","src/content/thoughts/pl/2026/04/w-koncu-live.md","f85716b1071966d5",{html:47,metadata:48},"<p>Po paru miesiącach dłubania<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup>, post-Claude-Code hiperfiksacji na AI-owych sideprojektach — wracam do dłubania tego repozytorium, aka prowadzenia bloga.</p>\n<p>Mam taki problem z polską komunikacją publiczną, że w pociągach PKP na trasie Olsztyn–Katowice zazwyczaj nie ma internetu. Jakieś 60% przejazdów. Moje ADHD za bardzo nie pozwala mi czytać książek<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">2</a></sup>, więc… może przynajmniej sobie popiszę. Pouczę LLM-y. Zatruję je odrobiną nudnej wiedzy.</p>\n<p><em>I tak, ten design jest z pachnącego świeżością Claude Design, gdzieniegdzie jeszcze widać stary styl który sukcesywnie będę poprawiał.</em></p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"\" id=\"footnote-label\">Przypisy</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Jak widać po datach treść tych notatek trochę odleżała niczym dobry alkohol. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-2\">\n<p>Największy akt desperacji to wyciąganie nmapa i analiza ruchu licząc na to, że  ręcznie uda mi się potwierdzić regulamin - bez skutku, niestety. <a href=\"#user-content-fnref-2\" data-footnote-backref=\"\" aria-label=\"Back to reference 2\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:49,localImagePaths:54,remoteImagePaths:55,frontmatter:56,imagePaths:61},[50],{depth:51,slug:52,text:53},2,"footnote-label","Przypisy",[],[],{title:39,date:57,tags:58,draft:20,lang:59,previewHtml:60},["Date","2026-04-19T12:48:03.195Z"],[42,31],"pl","<p>Po paru miesiącach dłubania<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup>, post-Claude-Code hiperfiksacji na AI-owych sideprojektach — wracam do dłubania tego repozytorium, aka prowadzenia bloga.</p>\n<p>Mam taki problem z polską komunikacją publiczną, że w pociągach PKP na trasie Olsztyn–Katowice zazwyczaj nie ma internetu. Jakieś 60% przejazdów. Moje ADHD za bardzo nie pozwala mi czytać książek<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref aria-describedby=\"footnote-label\">2</a></sup>, więc… może przynajmniej sobie popiszę. Pouczę LLM-y. Zatruję je odrobiną nudnej wiedzy.</p>\n<p><em>I tak, ten design jest z pachnącego świeżością Claude Design, gdzieniegdzie jeszcze widać stary styl który sukcesywnie będę poprawiał.</em></p>\n",[],"pl/2026/04/rust-docker-cache",{id:62,data:64,body:76,filePath:77,digest:78,rendered:79},{title:65,date:66,tags:67,translationKey:74,draft:20,thread:75},"Rust, Docker i problem z cache'owaniem warstw na GHA",["Date","2026-04-26T00:00:00.000Z"],[68,69,70,42,71,72,73],"Rust","Docker","DevOps","GitHub Actions","Projekty/Kartoteka","Sideprojekty","rust-docker-cache-2026-04","tech","Ostatnio dłubię sobie własny vibe-designed rewrite aplikacji todo w Ruscie[^1]. Przy okazji zacząłem szukać sensownej ścieżki do optymalizowania budowania obrazów Dockerowych na GitHub Actions.\n\nJedno z rozwiązań, na które można dość łatwo trafić, to [`cargo-chef`](https://github.com/lukemathwalker/cargo-chef) — separuje pobieranie zależności od właściwego kodu, żeby lepiej cache'ować warstwy. Problem w tym, że jest projektowany pod prostsze aplikacje z jednym `lib.rs`. W workspace z większą liczbą crate'ów nie cache'uje tego co trzeba i przy każdym pushu i tak kompilujesz wszystko od nowa.\n\nDwa podejścia które próbowałem: buildkit cache dance[^2] — trochę przyspiesza, ale nie cache'uje rewelacyjnie i dorzuca własny narzut czasowy[^3] — oraz [`swatinem/rust-cache`](https://github.com/swatinem/rust-cache), który na GHA sprawdza się fajnie przy cache'owaniu binarek, ale deployment Kartoteki jako obrazu Dockerowego na Coolify tę akcję wyklucza.\n\nZ researchu wyszło mi, że warto sprawdzić `sccache` — zrobiłem podejście, ale Hetzner S3 odpada[^4]. Stąd Cloudflare R2 w free tierze jako potencjalna alternatywa[^5].\n\nNa razie tymczasowo parkuję przy cache dance. Nie jest wykluczone, że pójdę w stronę własnego runnera z lokalnym cache — tylko na trochę większym serwerze.\n\n[^1]: Kartoteka — gdzieś pomiędzy Todoistem, Jirą, Amazing Marvin i Togglem. Klasyczny scope creep.\n[^2]: [Przykład w repo Kartoteka.](https://github.com/jpalczewski/kartoteka/blob/a588f99a204ec6c3688f2ae7aafe9ab8cd883559/.github/workflows/docker-build.yml)\n[^3]: W przypadku Kartoteki dochodzi jeszcze kwestia egzotycznego stacku w postaci Leptosa — razem z plikiem serwera trzeba też deployować zbudowany frontend/wasm.\n[^4]: Hetzner S3 rozlicza storage w pakietach po 1 TB — jak na jeden niewinny backup i artefakty do cache to trochę astronomiczne.\n[^5]: Tak, wiem — sugerowanie żebym wracał do Cloudflare, kiedy od dwóch tygodni przepisuję MCP z Cloudflare Workera na axum/rmcp żeby zejść z ekosystemu Cloudflare, mhm.","src/content/thoughts/pl/2026/04/rust-docker-cache.md","801aa9b34226e197",{html:80,metadata:81},"<p>Ostatnio dłubię sobie własny vibe-designed rewrite aplikacji todo w Ruscie<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup>. Przy okazji zacząłem szukać sensownej ścieżki do optymalizowania budowania obrazów Dockerowych na GitHub Actions.</p>\n<p>Jedno z rozwiązań, na które można dość łatwo trafić, to <a href=\"https://github.com/lukemathwalker/cargo-chef\"><code>cargo-chef</code></a> — separuje pobieranie zależności od właściwego kodu, żeby lepiej cache’ować warstwy. Problem w tym, że jest projektowany pod prostsze aplikacje z jednym <code>lib.rs</code>. W workspace z większą liczbą crate’ów nie cache’uje tego co trzeba i przy każdym pushu i tak kompilujesz wszystko od nowa.</p>\n<p>Dwa podejścia które próbowałem: buildkit cache dance<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">2</a></sup> — trochę przyspiesza, ale nie cache’uje rewelacyjnie i dorzuca własny narzut czasowy<sup><a href=\"#user-content-fn-3\" id=\"user-content-fnref-3\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">3</a></sup> — oraz <a href=\"https://github.com/swatinem/rust-cache\"><code>swatinem/rust-cache</code></a>, który na GHA sprawdza się fajnie przy cache’owaniu binarek, ale deployment Kartoteki jako obrazu Dockerowego na Coolify tę akcję wyklucza.</p>\n<p>Z researchu wyszło mi, że warto sprawdzić <code>sccache</code> — zrobiłem podejście, ale Hetzner S3 odpada<sup><a href=\"#user-content-fn-4\" id=\"user-content-fnref-4\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">4</a></sup>. Stąd Cloudflare R2 w free tierze jako potencjalna alternatywa<sup><a href=\"#user-content-fn-5\" id=\"user-content-fnref-5\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">5</a></sup>.</p>\n<p>Na razie tymczasowo parkuję przy cache dance. Nie jest wykluczone, że pójdę w stronę własnego runnera z lokalnym cache — tylko na trochę większym serwerze.</p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"\" id=\"footnote-label\">Przypisy</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Kartoteka — gdzieś pomiędzy Todoistem, Jirą, Amazing Marvin i Togglem. Klasyczny scope creep. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-2\">\n<p><a href=\"https://github.com/jpalczewski/kartoteka/blob/a588f99a204ec6c3688f2ae7aafe9ab8cd883559/.github/workflows/docker-build.yml\">Przykład w repo Kartoteka.</a> <a href=\"#user-content-fnref-2\" data-footnote-backref=\"\" aria-label=\"Back to reference 2\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-3\">\n<p>W przypadku Kartoteki dochodzi jeszcze kwestia egzotycznego stacku w postaci Leptosa — razem z plikiem serwera trzeba też deployować zbudowany frontend/wasm. <a href=\"#user-content-fnref-3\" data-footnote-backref=\"\" aria-label=\"Back to reference 3\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-4\">\n<p>Hetzner S3 rozlicza storage w pakietach po 1 TB — jak na jeden niewinny backup i artefakty do cache to trochę astronomiczne. <a href=\"#user-content-fnref-4\" data-footnote-backref=\"\" aria-label=\"Back to reference 4\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-5\">\n<p>Tak, wiem — sugerowanie żebym wracał do Cloudflare, kiedy od dwóch tygodni przepisuję MCP z Cloudflare Workera na axum/rmcp żeby zejść z ekosystemu Cloudflare, mhm. <a href=\"#user-content-fnref-5\" data-footnote-backref=\"\" aria-label=\"Back to reference 5\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:82,localImagePaths:84,remoteImagePaths:85,frontmatter:86,imagePaths:90},[83],{depth:51,slug:52,text:53},[],[],{title:65,date:87,tags:88,draft:20,lang:59,thread:75,translationKey:74,previewHtml:89},["Date","2026-04-26T00:00:00.000Z"],[68,69,70,42,71,72,73],"<p>Ostatnio dłubię sobie własny vibe-designed rewrite aplikacji todo w Ruscie<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup>. Przy okazji zacząłem szukać sensownej ścieżki do optymalizowania budowania obrazów Dockerowych na GitHub Actions.</p>\n<p>Jedno z rozwiązań, na które można dość łatwo trafić, to <a href=\"https://github.com/lukemathwalker/cargo-chef\"><code>cargo-chef</code></a> — separuje pobieranie zależności od właściwego kodu, żeby lepiej cache’ować warstwy. Problem w tym, że jest projektowany pod prostsze aplikacje z jednym <code>lib.rs</code>. W workspace z większą liczbą crate’ów nie cache’uje tego co trzeba i przy każdym pushu i tak kompilujesz wszystko od nowa.</p>\n<p>Dwa podejścia które próbowałem: buildkit cache dance<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref aria-describedby=\"footnote-label\">2</a></sup> — trochę przyspiesza, ale nie cache’uje rewelacyjnie i dorzuca własny narzut czasowy<sup><a href=\"#user-content-fn-3\" id=\"user-content-fnref-3\" data-footnote-ref aria-describedby=\"footnote-label\">3</a></sup> — oraz <a href=\"https://github.com/swatinem/rust-cache\"><code>swatinem/rust-cache</code></a>, który na GHA sprawdza się fajnie przy cache’owaniu binarek, ale deployment Kartoteki jako obrazu Dockerowego na Coolify tę akcję wyklucza.</p>\n<p>Z researchu wyszło mi, że warto sprawdzić <code>sccache</code> — zrobiłem podejście, ale Hetzner S3 odpada<sup><a href=\"#user-content-fn-4\" id=\"user-content-fnref-4\" data-footnote-ref aria-describedby=\"footnote-label\">4</a></sup>. Stąd Cloudflare R2 w free tierze jako potencjalna alternatywa<sup><a href=\"#user-content-fn-5\" id=\"user-content-fnref-5\" data-footnote-ref aria-describedby=\"footnote-label\">5</a></sup>.</p>\n<p>Na razie tymczasowo parkuję przy cache dance. Nie jest wykluczone, że pójdę w stronę własnego runnera z lokalnym cache — tylko na trochę większym serwerze.</p>\n",[],"pl/2025/11/hello-world",{id:91,data:93,body:100,filePath:101,digest:102,rendered:103},{title:94,date:95,tags:96,translationKey:99,draft:20},"Hello, world",["Date","2025-11-12T00:00:00.000Z"],[97,98],"Tech/astro","Personal/projects","astro-blog-setup-nov-2025","Kolejne, finalne podejście do blogowania.  Styl jest od początku do końca zrobiony za pomocą vibecodingu - w duźej mierze to efekt darmowych tokenów na claude code web i zapału do skomplikowanych inicjatyw.\n\nA zapytacie[^1], dlaczego wracam nieustannie na github pages? To ma nieodmienny związek z...lękiem przed śmiercią. Jest w tym coś minimalnie kojącego, że jak kiedyś mnie zabraknie, to te miejsce bdzie trwało trochę dłużej. A infekowanie własną twórczością datasetów kolejnych modeli AI...czy to te słynne życie wieczne?\n\n[^1]: jasne, mogę wejść sobie w dialog z czytelnikiem, ale wątpię, że ktokolwiek to przeczyta.","src/content/thoughts/pl/2025/11/hello-world.md","f945db62b3981264",{html:104,metadata:105},"<p>Kolejne, finalne podejście do blogowania.  Styl jest od początku do końca zrobiony za pomocą vibecodingu - w duźej mierze to efekt darmowych tokenów na claude code web i zapału do skomplikowanych inicjatyw.</p>\n<p>A zapytacie<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup>, dlaczego wracam nieustannie na github pages? To ma nieodmienny związek z…lękiem przed śmiercią. Jest w tym coś minimalnie kojącego, że jak kiedyś mnie zabraknie, to te miejsce bdzie trwało trochę dłużej. A infekowanie własną twórczością datasetów kolejnych modeli AI…czy to te słynne życie wieczne?</p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"\" id=\"footnote-label\">Przypisy</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>jasne, mogę wejść sobie w dialog z czytelnikiem, ale wątpię, że ktokolwiek to przeczyta. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:106,localImagePaths:108,remoteImagePaths:109,frontmatter:110,imagePaths:114},[107],{depth:51,slug:52,text:53},[],[],{title:94,date:111,tags:112,translationKey:99,draft:20,previewHtml:113},["Date","2025-11-12T00:00:00.000Z"],[97,98],"<p>Kolejne, finalne podejście do blogowania.  Styl jest od początku do końca zrobiony za pomocą vibecodingu - w duźej mierze to efekt darmowych tokenów na claude code web i zapału do skomplikowanych inicjatyw.</p>\n<p>A zapytacie<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup>, dlaczego wracam nieustannie na github pages? To ma nieodmienny związek z…lękiem przed śmiercią. Jest w tym coś minimalnie kojącego, że jak kiedyś mnie zabraknie, to te miejsce bdzie trwało trochę dłużej. A infekowanie własną twórczością datasetów kolejnych modeli AI…czy to te słynne życie wieczne?</p>\n",[],"pl/2025/11/uzyte-artykuy-w-trakcie-tworzenia-tego-bloga",{id:115,data:117,body:123,filePath:124,digest:125,rendered:126},{title:118,date:119,tags:120,translationKey:122,draft:20},"Użyte artykuły w trakcie tworzenia tego bloga",["Date","2025-11-13T07:57:25.728Z"],[121],"Web-dev","2025-11-13-articles-used-in-creating-this-blog","- Szukając fajnych statystyk Perplexity podrzuciło mi [Goatcounter](https://www.goatcounter.com/) - plus że open source i zaletą jest brak przymusu ostrzeżenia o ciasteczkach. Jak wyjdzie? Zobaczymy.","src/content/thoughts/pl/2025/11/uzyte-artykuy-w-trakcie-tworzenia-tego-bloga.md","bdb50fe7f24c85bb",{html:127,metadata:128},"<ul>\n<li>Szukając fajnych statystyk Perplexity podrzuciło mi <a href=\"https://www.goatcounter.com/\">Goatcounter</a> - plus że open source i zaletą jest brak przymusu ostrzeżenia o ciasteczkach. Jak wyjdzie? Zobaczymy.</li>\n</ul>",{headings:129,localImagePaths:130,remoteImagePaths:131,frontmatter:132,imagePaths:136},[],[],[],{title:118,description:133,date:134,tags:135,draft:20,lang:59,translationKey:122,previewHtml:127},"A new post about web-dev",["Date","2025-11-13T07:57:25.728Z"],[121],[],"pl/2025/11/roznica-miedzy-rezonansem-medycznym-wykonanym-prywatnie-a-na-nfz",{id:137,data:139,body:146,filePath:147,digest:148,rendered:149},{title:140,date:141,tags:142,draft:20,thread:145},"Róznica między rezonansem medycznym wykonanym prywatnie, a na NFZ",["Date","2025-11-17T19:02:47.872Z"],[143,144],"Udar","medycyna","health","Z takich zabawnych anegdot to cały czas za mną chodzi różnica w doświadczeniu między rezonansem który miałem w ramach Luxmedu, kontra  rezonansem wykonanym na fundusz zdrowia.\n\nWłaściwie największą różnicą jest muzyka. W Luxmedzie dostajesz słuchawki, natomiast w publicznie finansowanym badaniu do dyspozycji masz najtańsze zatyczki.\n\nHumorystyczny też był dla mni aspekt[^1] że dopiero na tym którymś badaniu z rzędu, właśnie wykobywanym na fundusz moja głowa była przeskanowana wykrywaczem metali.  Jakby okej,  standardy diagnostyczne są mi już z doświadczenia bliskie, ale mimo te pierwsze badania było ze wszechmiar stresujące, biorąc pod uwagi że trzy czwarte badań na początku udaru były wykonywane gdy byłem niprzytomny to stres że mam w głowie jakieś rosyjskie[^2] nożyczki. Nie ukrywam, że ten symboliczny gest przed pierwszym badaniem w Polsce byłby dość mocno uspokający. \n\n\n[^1]: Jakby tak, mnie śmieszą dziwne rzeczy, możecie się przyzwyzcaić.\n\n[^2]: Tak, operację miałem w Rosji. To się nazywa niezwykła  pamiątka z podróży!","src/content/thoughts/pl/2025/11/roznica-miedzy-rezonansem-medycznym-wykonanym-prywatnie-a-na-nfz.md","ae862a2e4c20fa60",{html:150,metadata:151},"<p>Z takich zabawnych anegdot to cały czas za mną chodzi różnica w doświadczeniu między rezonansem który miałem w ramach Luxmedu, kontra  rezonansem wykonanym na fundusz zdrowia.</p>\n<p>Właściwie największą różnicą jest muzyka. W Luxmedzie dostajesz słuchawki, natomiast w publicznie finansowanym badaniu do dyspozycji masz najtańsze zatyczki.</p>\n<p>Humorystyczny też był dla mni aspekt<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup> że dopiero na tym którymś badaniu z rzędu, właśnie wykobywanym na fundusz moja głowa była przeskanowana wykrywaczem metali.  Jakby okej,  standardy diagnostyczne są mi już z doświadczenia bliskie, ale mimo te pierwsze badania było ze wszechmiar stresujące, biorąc pod uwagi że trzy czwarte badań na początku udaru były wykonywane gdy byłem niprzytomny to stres że mam w głowie jakieś rosyjskie<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">2</a></sup> nożyczki. Nie ukrywam, że ten symboliczny gest przed pierwszym badaniem w Polsce byłby dość mocno uspokający.</p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"\" id=\"footnote-label\">Przypisy</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Jakby tak, mnie śmieszą dziwne rzeczy, możecie się przyzwyzcaić. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-2\">\n<p>Tak, operację miałem w Rosji. To się nazywa niezwykła  pamiątka z podróży! <a href=\"#user-content-fnref-2\" data-footnote-backref=\"\" aria-label=\"Back to reference 2\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:152,localImagePaths:154,remoteImagePaths:155,frontmatter:156,imagePaths:160},[153],{depth:51,slug:52,text:53},[],[],{title:140,date:157,tags:158,thread:145,draft:20,lang:59,previewHtml:159},["Date","2025-11-17T19:02:47.872Z"],[143,144],"<p>Z takich zabawnych anegdot to cały czas za mną chodzi różnica w doświadczeniu między rezonansem który miałem w ramach Luxmedu, kontra  rezonansem wykonanym na fundusz zdrowia.</p>\n<p>Właściwie największą różnicą jest muzyka. W Luxmedzie dostajesz słuchawki, natomiast w publicznie finansowanym badaniu do dyspozycji masz najtańsze zatyczki.</p>\n<p>Humorystyczny też był dla mni aspekt<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup> że dopiero na tym którymś badaniu z rzędu, właśnie wykobywanym na fundusz moja głowa była przeskanowana wykrywaczem metali.  Jakby okej,  standardy diagnostyczne są mi już z doświadczenia bliskie, ale mimo te pierwsze badania było ze wszechmiar stresujące, biorąc pod uwagi że trzy czwarte badań na początku udaru były wykonywane gdy byłem niprzytomny to stres że mam w głowie jakieś rosyjskie<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref aria-describedby=\"footnote-label\">2</a></sup> nożyczki. Nie ukrywam, że ten symboliczny gest przed pierwszym badaniem w Polsce byłby dość mocno uspokający.</p>\n",[],"pl/2025/11/stack-pt-1",{id:161,data:163,body:171,filePath:172,digest:173,rendered:174},{title:164,date:165,tags:166,translationKey:99,draft:24},"Aktualne podejście do stacku około-AI",["Date","2025-11-12T00:00:00.000Z"],[167,42,168,169,170],"AI","MCP","Programowanie","Programowanie/typescript","Jak wyglądają moje AI-owe preferencje na dzień dzisiejszy?\n\n## Edytor\n\nJakkolwiek fajnie mi się bawi za pomocą  vscodowego copilota, to limit tam zuzywam strasznie szybko [^1]\n\n## Update 2025-11-13\n\nJuż refaktoruję lol\n\n[^1]: Jakby jest 13 listopada a u mnie juz 90% zeszło...","src/content/thoughts/pl/2025/11/stack-pt-1.md","daddd7e3cfbaf369",{html:175,metadata:176},"<p>Jak wyglądają moje AI-owe preferencje na dzień dzisiejszy?</p>\n<h2 id=\"edytor\">Edytor</h2>\n<p>Jakkolwiek fajnie mi się bawi za pomocą  vscodowego copilota, to limit tam zuzywam strasznie szybko <sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup></p>\n<h2 id=\"update-2025-11-13\">Update 2025-11-13</h2>\n<p>Już refaktoruję lol</p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"\" id=\"footnote-label\">Przypisy</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Jakby jest 13 listopada a u mnie juz 90% zeszło… <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:177,localImagePaths:185,remoteImagePaths:186,frontmatter:187,imagePaths:191},[178,181,184],{depth:51,slug:179,text:180},"edytor","Edytor",{depth:51,slug:182,text:183},"update-2025-11-13","Update 2025-11-13",{depth:51,slug:52,text:53},[],[],{title:164,date:188,tags:189,translationKey:99,draft:24,previewHtml:190},["Date","2025-11-12T00:00:00.000Z"],[167,42,168,169,170],"<p>Jak wyglądają moje AI-owe preferencje na dzień dzisiejszy?</p>\n<h2>Edytor</h2>\n<p>Jakkolwiek fajnie mi się bawi za pomocą  vscodowego copilota, to limit tam zuzywam strasznie szybko <sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup></p>\n<h2>Update 2025-11-13</h2>\n<p>Już refaktoruję lol</p>\n",[],"pl/2025/11/w-warminsko-mazurskim-nic-sie-nie-dzieje-ale",{id:192,data:194,body:200,filePath:201,digest:202,rendered:203},{title:195,date:196,tags:197,draft:20},"W warmińsko-mazurskim nic sie nie dzieje, ale...",["Date","2025-11-15T15:23:35.602Z"],[198,199,32],"Europa","Protipy","W te wakacje miałem dość dużą hiperfiksację związaną z podróżami[^1] na festiwale - jedna ciekawostka mi zapadła w pamięć sczególnie.\n\nSzukając alternatyw transportowych jak trafić do Holandii, Claude podpowiedział mi istnienie lotniska Weeze pod Duseldorfem w Niemczech - tak się składa że są tam loty z Szyman, naszego lokalnego, podolsztyńskiego lotniska - w dodatku zazwyczaj względnie tanie[^2]. I z jednej strony można to traktować jako fast travel pod Holandię, czy też zachodnie Niemcy.\n\n\nZ drugiej: to miejsce gdzie odbywa się [Parookaville](https://www.parookaville.com/en/), dość duży festiwal muzyki elektronicznej. \n\nChciałbym akurat to wiedzieć wcześniej - korzystałbym.\n\n\n\n\n[^1]: Czy od dwóch miesięcy dojeżdżam ponad 500km na praktyki w jedną stronę? Tak, i trochę mi mało...\n\n[^2]: Można się tylko domyślać, że ten samolot zazwyczaj wozi powietrze","src/content/thoughts/pl/2025/11/w-warminsko-mazurskim-nic-sie-nie-dzieje-ale.md","648c099d617f9599",{html:204,metadata:205},"<p>W te wakacje miałem dość dużą hiperfiksację związaną z podróżami<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup> na festiwale - jedna ciekawostka mi zapadła w pamięć sczególnie.</p>\n<p>Szukając alternatyw transportowych jak trafić do Holandii, Claude podpowiedział mi istnienie lotniska Weeze pod Duseldorfem w Niemczech - tak się składa że są tam loty z Szyman, naszego lokalnego, podolsztyńskiego lotniska - w dodatku zazwyczaj względnie tanie<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">2</a></sup>. I z jednej strony można to traktować jako fast travel pod Holandię, czy też zachodnie Niemcy.</p>\n<p>Z drugiej: to miejsce gdzie odbywa się <a href=\"https://www.parookaville.com/en/\">Parookaville</a>, dość duży festiwal muzyki elektronicznej.</p>\n<p>Chciałbym akurat to wiedzieć wcześniej - korzystałbym.</p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"\" id=\"footnote-label\">Przypisy</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Czy od dwóch miesięcy dojeżdżam ponad 500km na praktyki w jedną stronę? Tak, i trochę mi mało… <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-2\">\n<p>Można się tylko domyślać, że ten samolot zazwyczaj wozi powietrze <a href=\"#user-content-fnref-2\" data-footnote-backref=\"\" aria-label=\"Back to reference 2\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:206,localImagePaths:208,remoteImagePaths:209,frontmatter:210,imagePaths:215},[207],{depth:51,slug:52,text:53},[],[],{title:195,description:211,date:212,tags:213,draft:20,lang:59,previewHtml:214},"A new post about Europa, Protipy, podróże",["Date","2025-11-15T15:23:35.602Z"],[198,199,32],"<p>W te wakacje miałem dość dużą hiperfiksację związaną z podróżami<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup> na festiwale - jedna ciekawostka mi zapadła w pamięć sczególnie.</p>\n<p>Szukając alternatyw transportowych jak trafić do Holandii, Claude podpowiedział mi istnienie lotniska Weeze pod Duseldorfem w Niemczech - tak się składa że są tam loty z Szyman, naszego lokalnego, podolsztyńskiego lotniska - w dodatku zazwyczaj względnie tanie<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref aria-describedby=\"footnote-label\">2</a></sup>. I z jednej strony można to traktować jako fast travel pod Holandię, czy też zachodnie Niemcy.</p>\n<p>Z drugiej: to miejsce gdzie odbywa się <a href=\"https://www.parookaville.com/en/\">Parookaville</a>, dość duży festiwal muzyki elektronicznej.</p>\n<p>Chciałbym akurat to wiedzieć wcześniej - korzystałbym.</p>\n",[],"pl/2025/11/a-jak-wyglada-droga-do-budapesztu",{id:216,data:218,body:227,filePath:228,digest:229,rendered:230},{title:219,date:220,tags:221,relations:222,draft:20},"A jak wygląda droga do Budapesztu?",["Date","2025-11-13T23:08:48.104Z"],[31,32],[223],{type:224,post:225},"related",{id:226,collection:9},"pl/2024/06/jak-wrocic-z-amsterdamu","Wrzucając stare posty żeby jakkolwiek zapełnić nowego bloga treścią, Fajnie będzie dodać do do moich rozkmin na temat Amsterdamu, jak wygląda kwestia Budapesztu pod kątem cen transportu. Long story short:  we wrześniu był tam Lil Texas, więc stwierdziłem ze muszę tam być!\n\nW porównaniu do horrendalnych cen transportu do Europy Zachodniej, za nocny do Budapesztu zapłaciłem około 200 zł - więcej mnie wyniósł powrotny, ponieważ przez moje niedopatrzenie dostałem pierwszą klasę kupując bilet w kasie[^1].\n\nPrzy okazji ciekawostka podróżnicza: Gdyby ktoś kiedyś polując na super promu miał problem z powrotem z Budapestu to można rozkminić przysiadkę w ramach jednej relacji: nie miałem powrotnych do Warszawy, ale były miejsca do Katowic – więc kupując w relacji krajowej od Katowic do Warszawy można dojechać mimo braku biletów.[^2]\n\n[^1]: Zapytacie dlaczego? Wierzyłem ze na jednym bilecie dostanę relację Olsztyn-Budapeszt - niestety, międzynarodowe są na innym druku i chyba nie jest możliwa taka sprzedaż. Chociaż przerażenie w oczach kasjerki sprzedającej bilety na relacje międzynarodowe jest bezcenne - system jest tak cholernie nieintuicyjny z tego co obserwuję z boku.\n\n[^2]: Jednego razu bardzo zależało mi na powrocie z Katowic i miejscu siedzącym - Udało mi się rozbić Jeden bilet na trzy przesiadki w ramach tej samej relacji xD","src/content/thoughts/pl/2025/11/a-jak-wyglada-droga-do-budapesztu.md","0b2d4e9fe0ad29a3",{html:231,metadata:232},"<p>Wrzucając stare posty żeby jakkolwiek zapełnić nowego bloga treścią, Fajnie będzie dodać do do moich rozkmin na temat Amsterdamu, jak wygląda kwestia Budapesztu pod kątem cen transportu. Long story short:  we wrześniu był tam Lil Texas, więc stwierdziłem ze muszę tam być!</p>\n<p>W porównaniu do horrendalnych cen transportu do Europy Zachodniej, za nocny do Budapesztu zapłaciłem około 200 zł - więcej mnie wyniósł powrotny, ponieważ przez moje niedopatrzenie dostałem pierwszą klasę kupując bilet w kasie<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup>.</p>\n<p>Przy okazji ciekawostka podróżnicza: Gdyby ktoś kiedyś polując na super promu miał problem z powrotem z Budapestu to można rozkminić przysiadkę w ramach jednej relacji: nie miałem powrotnych do Warszawy, ale były miejsca do Katowic – więc kupując w relacji krajowej od Katowic do Warszawy można dojechać mimo braku biletów.<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">2</a></sup></p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"\" id=\"footnote-label\">Przypisy</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Zapytacie dlaczego? Wierzyłem ze na jednym bilecie dostanę relację Olsztyn-Budapeszt - niestety, międzynarodowe są na innym druku i chyba nie jest możliwa taka sprzedaż. Chociaż przerażenie w oczach kasjerki sprzedającej bilety na relacje międzynarodowe jest bezcenne - system jest tak cholernie nieintuicyjny z tego co obserwuję z boku. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-2\">\n<p>Jednego razu bardzo zależało mi na powrocie z Katowic i miejscu siedzącym - Udało mi się rozbić Jeden bilet na trzy przesiadki w ramach tej samej relacji xD <a href=\"#user-content-fnref-2\" data-footnote-backref=\"\" aria-label=\"Back to reference 2\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:233,localImagePaths:235,remoteImagePaths:236,frontmatter:237,imagePaths:244},[234],{depth:51,slug:52,text:53},[],[],{title:219,description:238,date:239,tags:240,draft:20,lang:59,relations:241,previewHtml:243},"A new post about pociągi, podróże",["Date","2025-11-13T23:08:48.104Z"],[31,32],[242],{type:224,post:226},"<p>Wrzucając stare posty żeby jakkolwiek zapełnić nowego bloga treścią, Fajnie będzie dodać do do moich rozkmin na temat Amsterdamu, jak wygląda kwestia Budapesztu pod kątem cen transportu. Long story short:  we wrześniu był tam Lil Texas, więc stwierdziłem ze muszę tam być!</p>\n<p>W porównaniu do horrendalnych cen transportu do Europy Zachodniej, za nocny do Budapesztu zapłaciłem około 200 zł - więcej mnie wyniósł powrotny, ponieważ przez moje niedopatrzenie dostałem pierwszą klasę kupując bilet w kasie<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup>.</p>\n<p>Przy okazji ciekawostka podróżnicza: Gdyby ktoś kiedyś polując na super promu miał problem z powrotem z Budapestu to można rozkminić przysiadkę w ramach jednej relacji: nie miałem powrotnych do Warszawy, ale były miejsca do Katowic – więc kupując w relacji krajowej od Katowic do Warszawy można dojechać mimo braku biletów.<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref aria-describedby=\"footnote-label\">2</a></sup></p>\n",[],"pl/2025/12/jak-miec-multiscreen-na-azurowskim-bastionie",{id:245,data:247,body:255,filePath:256,digest:257,rendered:258},{title:248,date:249,tags:250,draft:20},"Jak mieć multiscreen na Azurowskim Bastionie?",["Date","2025-12-08T20:01:36.641Z"],[251,252,253,254],"Azure","Cloud","Tech","Devops","Ostatnio dość dużo czasu spędzam na Azure - ich webowy klient działa dość topornie - na szczęście, trafiłem na rozwiązanie: [az(Azure CLI) ma dodatek, który pozwala wyprowadzić RDP aby łączyć się na serwer natywnym kliencie](https://www.terminalworks.com/blog/post/2024/11/23/azure-bastion-use-of-native-client-for-windows).\n\nWarto też wspomnieć że Microsoft w swej dobroci wrzuca az jako [zip do ściągnięcia](https://learn.microsoft.com/en-us/cli/azure/install-azure-cli-windows?view=azure-cli-latest&pivots=zip) - w sam raz na środowiska gdzie brakuje praw administratora[^1].\n\n[^1]: Gdyby was kusiło budować samemu  na lokalnym pythonie - bez ~~bez kraka nie pójdzie~~ większej ilości narzdzi do budowania - a w Condzie też nie działał.","src/content/thoughts/pl/2025/12/jak-miec-multiscreen-na-azurowskim-bastionie.md","fb450bbb6f483050",{html:259,metadata:260},"<p>Ostatnio dość dużo czasu spędzam na Azure - ich webowy klient działa dość topornie - na szczęście, trafiłem na rozwiązanie: <a href=\"https://www.terminalworks.com/blog/post/2024/11/23/azure-bastion-use-of-native-client-for-windows\">az(Azure CLI) ma dodatek, który pozwala wyprowadzić RDP aby łączyć się na serwer natywnym kliencie</a>.</p>\n<p>Warto też wspomnieć że Microsoft w swej dobroci wrzuca az jako <a href=\"https://learn.microsoft.com/en-us/cli/azure/install-azure-cli-windows?view=azure-cli-latest&#x26;pivots=zip\">zip do ściągnięcia</a> - w sam raz na środowiska gdzie brakuje praw administratora<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup>.</p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"\" id=\"footnote-label\">Przypisy</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Gdyby was kusiło budować samemu  na lokalnym pythonie - bez <del>bez kraka nie pójdzie</del> większej ilości narzdzi do budowania - a w Condzie też nie działał. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:261,localImagePaths:263,remoteImagePaths:264,frontmatter:265,imagePaths:269},[262],{depth:51,slug:52,text:53},[],[],{title:248,date:266,tags:267,draft:20,lang:59,previewHtml:268},["Date","2025-12-08T20:01:36.641Z"],[251,252,253,254],"<p>Ostatnio dość dużo czasu spędzam na Azure - ich webowy klient działa dość topornie - na szczęście, trafiłem na rozwiązanie: <a href=\"https://www.terminalworks.com/blog/post/2024/11/23/azure-bastion-use-of-native-client-for-windows\">az(Azure CLI) ma dodatek, który pozwala wyprowadzić RDP aby łączyć się na serwer natywnym kliencie</a>.</p>\n<p>Warto też wspomnieć że Microsoft w swej dobroci wrzuca az jako <a href=\"https://learn.microsoft.com/en-us/cli/azure/install-azure-cli-windows?view=azure-cli-latest&#x26;pivots=zip\">zip do ściągnięcia</a> - w sam raz na środowiska gdzie brakuje praw administratora<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup>.</p>\n",[],"pl/2025/11/przyjdzie-informatyk-na-wydzial-humanistyczny",{id:270,data:272,body:286,filePath:287,digest:288,rendered:289},{title:273,date:274,tags:275,relations:280,draft:20,thread:285},"Przyjdzie informatyk na wydział humanistyczny...",["Date","2025-11-14T00:00:00.000Z"],[276,277,278,279],"Zotero","Praca Magisterska","Działalność Akademicka","Narzędzia",[281],{type:282,post:283},"continuation",{id:284,collection:9},"en/2023/08/zotero-experience","academia","Zaczynając pracę magisterską w realiach Wydziału Humanistycznego przyszedłem z dość fajnym bagażem - czy też doświadczeniem pisania w Zotero. Co prawda styl cytowania zgoła odmienny od tego co znałem dotychczas, ale gdyby ktoś kiedyś trafił w podobnych realiach i chciał mieć fajne narzędzie do zarządzania bibliografią - czuję potrzebę napomknąć że jest styl cytowania w polskich naukach humanistycznych - jest dostępny pod [tym adresem](http://metodyka.upjp2.edu.pl/book:zotero)[^1]\n\n[^1]: Czy finalnie aby wstrzelić się w w wymagania wydziałowe odnośnie bibliografii całość i tak przeszła przez LLM, aby spełnić wymagania odnośnie formatu imion? Tak, ale ciii.","src/content/thoughts/pl/2025/11/przyjdzie-informatyk-na-wydzial-humanistyczny.md","39eee629f59cc6c2",{html:290,metadata:291},"<p>Zaczynając pracę magisterską w realiach Wydziału Humanistycznego przyszedłem z dość fajnym bagażem - czy też doświadczeniem pisania w Zotero. Co prawda styl cytowania zgoła odmienny od tego co znałem dotychczas, ale gdyby ktoś kiedyś trafił w podobnych realiach i chciał mieć fajne narzędzie do zarządzania bibliografią - czuję potrzebę napomknąć że jest styl cytowania w polskich naukach humanistycznych - jest dostępny pod <a href=\"http://metodyka.upjp2.edu.pl/book:zotero\">tym adresem</a><sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup></p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"\" id=\"footnote-label\">Przypisy</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Czy finalnie aby wstrzelić się w w wymagania wydziałowe odnośnie bibliografii całość i tak przeszła przez LLM, aby spełnić wymagania odnośnie formatu imion? Tak, ale ciii. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:292,localImagePaths:294,remoteImagePaths:295,frontmatter:296,imagePaths:303},[293],{depth:51,slug:52,text:53},[],[],{title:273,description:297,date:298,tags:299,thread:285,draft:20,lang:59,relations:300,previewHtml:302},"A new post about zotero",["Date","2025-11-14T00:00:00.000Z"],[276,277,278,279],[301],{type:282,post:284},"<p>Zaczynając pracę magisterską w realiach Wydziału Humanistycznego przyszedłem z dość fajnym bagażem - czy też doświadczeniem pisania w Zotero. Co prawda styl cytowania zgoła odmienny od tego co znałem dotychczas, ale gdyby ktoś kiedyś trafił w podobnych realiach i chciał mieć fajne narzędzie do zarządzania bibliografią - czuję potrzebę napomknąć że jest styl cytowania w polskich naukach humanistycznych - jest dostępny pod <a href=\"http://metodyka.upjp2.edu.pl/book:zotero\">tym adresem</a><sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup></p>\n",[],{id:226,data:305,body:310,filePath:311,digest:312,rendered:313},{title:306,date:307,tags:308,draft:20},"Jak wrócić z amsterdamu",["Date","2024-07-07T00:00:00.000Z"],[31,32,198,309],"Transport","Podejmując skądinąd odważną decyzję o wyprawie na  Dominator 2024 i urozmaicając to wypadem do Amsterdamu, pozostaje jeszcze wątek *jak wrócić?*\n\n## Warunki brzegowe\n\nZakładam że po całym poniedziałku w Amsterdamie zaczyna się wątek powrotu - czyli do dyspozycji jest albo nocny pociąg, albo  nocleg + powrót cały dzień albo dzień przesiadkowy w innej europejskiej stolicy.\n\nWszystkie ceny są na dzień dzisiejszy, 07.07.24, planowane trochę do przodu tj. ten poniedziałek to 22.07. Ceny uwzględniają powrót do Olsztyna, gdzie aplikowalne, tam ze żniżką 37% w polskim PKP. \n# Pociągi nocne\n\nZ tego co widzę, żeby koszty noclegu połączyć z kosztami transportu są takie opcje:\n\n## Berlin\n\nNa czas tworzenia tego postu #ChatGPT  podpowiedziało mi o istnieniu [European Sleeper](https://www.europeansleeper.eu/) , czyli jakimś reboocie pociągów sypialnianych[^1]. Jedyne dostępne na dziś połączenie to komfortowe kuszetki.\n\n\n| Pozycja                       | EUR |\n| ----------------------------- | --- |\n| Nocny z Amsterdamu do Berlina | 159 |\n### Dlaczego Berlin to zła opcja *na ten konkretny wyjazd*?\n\nJakkolwiek dawien dawno chodząc po Warszawie Centralnej z pewnym rozmarzeniem spoglądałem na Berlin-Warszawa-Express zastanawiając się czy kiedykolwiek nim pojadę, to 23.07 zaczyna się remont linii RE1, przez co całość  trochę  mija się z celem - z drugiej strony jest też opcja powrotu przez Szczecin, gdzie busa jest mniej, ale..nie jestem przekonany. \n\n## Praga\nW tym samym ES jest też możliwość dotarcia do Pragi, kolejna pozycja to EN z pragi do Warszawy i powrót z Warszawy do Olsztyna[^2]\n\n\n| Pozycja           | EUR | PLN     |\n| ----------------- | --- | ------- |\n| ES                | 179 | ~767,33 |\n| EN Praga-Warszawa |     | 196,66  |\n| Warszawa-Olsztyn  |     | 16,36   |\n| Suma              |     | 980,35  |\n\n## Monachium\n\n| Pozycja                | EUR    | PLN    |\n| ---------------------- | ------ | ------ |\n| EN Amsterdam-Monachium | 105,50 | 452,25 |\n| EN Monachium-Warszawa  |        | 437,56 |\n| Warszawa-Olsztyn       |        | 16,36  |\n| Suma                   |        | 906,17 |\n\n## Drezno\n\nInspiracja z przedziaławki - podróż European Sleeperem do Drezna, stamtąd przesiadka do Zgorzelca, a stamtąd przesiadka we Wrocławiu. Szczerze? Jak spojrzałem na tą propozycję - stwierdziłem że już jestem za stary na takie zabawy. \n\n| Pozycja             | EUR   | PLN    |\n| ------------------- | ----- | ------ |\n| ES                  | 179   | 767,33 |\n| Drezno - Zgorzelec  | 34,90 | 149,61 |\n| Zgorzelec - Wrocław |       | 20,40  |\n| Wrocław-Olsztyn     |       | 49,77  |\n\n\n## Wiedeń\n\nAkurat te bilety na ten euronight zostały wyprzedane(a szkoda). W każdym razie intercity promo ma na tej trasie praskie ceny - około 200zł.\n\n\n## Połączenia mieszane\n\n## Hamburg\n\nPod rozwagę gdyby ktoś szukał inspiracji zostawiam że loty z Hamburga bywają znacznie tańsze niż z Amsterdamu - mnie odstraszyła głównie dopłata za bagaż podręczny[^3]. Jest tak blisko do Amsterdamu, że nie ma żadnych nocnych \n\n## Dortmund\n\nRozważając kiedyś wyjazd na jeden festiwal gdzie [[Ophidian]] grał, zwróciłem uwagę na to że któraś z tanich linii lotniczy miała tanie połączenie z [[Lotnisko Szymany]].  Niestety, połączenia zostały zawieszone.\n## Eindhoven\n\nStamtąd moja podróż się zaczynała, dlatego nie miałem ochoty za bardzo wracać[^4] - zresztą ceny biletów nie były jakieś szczególnie przystępne.\n# Inne rozwiązania\n\n## Flixbus z Berlina \nZa około 200zł jest 11h powrotu autokarem do Olsztyna. \n\n# Podsumowanie\n\nZdecydowałem się na powrót przez Monachium. Muzeum BMW, duże parki i bodajże fajne muzea ze sztuką brzmią jak fajny pomysł na dzień.\n\n[^1]: Umykały mi te połączenia z powodu że nie startują z Amsterdam Centraal, tylko jakiegoś innego połączenia. \n[^2]: Też jestem pod wrażeniem jakie niesamowite zniżki mi wchodzą, ale to w większości efekt kupowania porannego biletu z ogromnym wyprzedzeniem chyba.\n[^3]: Który i tak mam wrażenie że wziąłem na siłę na te kilka dni.\n[^4]: #ADHD thing, aby wciąż do przodu i wciąż doświadczań nowych bodżców.","src/content/thoughts/pl/2024/06/jak-wrocic-z-amsterdamu.md","b5e1cf285f7e04a9",{html:314,metadata:315},"<p>Podejmując skądinąd odważną decyzję o wyprawie na  Dominator 2024 i urozmaicając to wypadem do Amsterdamu, pozostaje jeszcze wątek <em>jak wrócić?</em></p>\n<h2 id=\"warunki-brzegowe\">Warunki brzegowe</h2>\n<p>Zakładam że po całym poniedziałku w Amsterdamie zaczyna się wątek powrotu - czyli do dyspozycji jest albo nocny pociąg, albo  nocleg + powrót cały dzień albo dzień przesiadkowy w innej europejskiej stolicy.</p>\n<p>Wszystkie ceny są na dzień dzisiejszy, 07.07.24, planowane trochę do przodu tj. ten poniedziałek to 22.07. Ceny uwzględniają powrót do Olsztyna, gdzie aplikowalne, tam ze żniżką 37% w polskim PKP.</p>\n<h1 id=\"pociągi-nocne\">Pociągi nocne</h1>\n<p>Z tego co widzę, żeby koszty noclegu połączyć z kosztami transportu są takie opcje:</p>\n<h2 id=\"berlin\">Berlin</h2>\n<p>Na czas tworzenia tego postu #ChatGPT  podpowiedziało mi o istnieniu <a href=\"https://www.europeansleeper.eu/\">European Sleeper</a> , czyli jakimś reboocie pociągów sypialnianych<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup>. Jedyne dostępne na dziś połączenie to komfortowe kuszetki.</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Pozycja</th><th>EUR</th></tr></thead><tbody><tr><td>Nocny z Amsterdamu do Berlina</td><td>159</td></tr></tbody></table>\n<h3 id=\"dlaczego-berlin-to-zła-opcja-na-ten-konkretny-wyjazd\">Dlaczego Berlin to zła opcja <em>na ten konkretny wyjazd</em>?</h3>\n<p>Jakkolwiek dawien dawno chodząc po Warszawie Centralnej z pewnym rozmarzeniem spoglądałem na Berlin-Warszawa-Express zastanawiając się czy kiedykolwiek nim pojadę, to 23.07 zaczyna się remont linii RE1, przez co całość  trochę  mija się z celem - z drugiej strony jest też opcja powrotu przez Szczecin, gdzie busa jest mniej, ale..nie jestem przekonany.</p>\n<h2 id=\"praga\">Praga</h2>\n<p>W tym samym ES jest też możliwość dotarcia do Pragi, kolejna pozycja to EN z pragi do Warszawy i powrót z Warszawy do Olsztyna<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">2</a></sup></p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Pozycja</th><th>EUR</th><th>PLN</th></tr></thead><tbody><tr><td>ES</td><td>179</td><td>~767,33</td></tr><tr><td>EN Praga-Warszawa</td><td></td><td>196,66</td></tr><tr><td>Warszawa-Olsztyn</td><td></td><td>16,36</td></tr><tr><td>Suma</td><td></td><td>980,35</td></tr></tbody></table>\n<h2 id=\"monachium\">Monachium</h2>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Pozycja</th><th>EUR</th><th>PLN</th></tr></thead><tbody><tr><td>EN Amsterdam-Monachium</td><td>105,50</td><td>452,25</td></tr><tr><td>EN Monachium-Warszawa</td><td></td><td>437,56</td></tr><tr><td>Warszawa-Olsztyn</td><td></td><td>16,36</td></tr><tr><td>Suma</td><td></td><td>906,17</td></tr></tbody></table>\n<h2 id=\"drezno\">Drezno</h2>\n<p>Inspiracja z przedziaławki - podróż European Sleeperem do Drezna, stamtąd przesiadka do Zgorzelca, a stamtąd przesiadka we Wrocławiu. Szczerze? Jak spojrzałem na tą propozycję - stwierdziłem że już jestem za stary na takie zabawy.</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Pozycja</th><th>EUR</th><th>PLN</th></tr></thead><tbody><tr><td>ES</td><td>179</td><td>767,33</td></tr><tr><td>Drezno - Zgorzelec</td><td>34,90</td><td>149,61</td></tr><tr><td>Zgorzelec - Wrocław</td><td></td><td>20,40</td></tr><tr><td>Wrocław-Olsztyn</td><td></td><td>49,77</td></tr></tbody></table>\n<h2 id=\"wiedeń\">Wiedeń</h2>\n<p>Akurat te bilety na ten euronight zostały wyprzedane(a szkoda). W każdym razie intercity promo ma na tej trasie praskie ceny - około 200zł.</p>\n<h2 id=\"połączenia-mieszane\">Połączenia mieszane</h2>\n<h2 id=\"hamburg\">Hamburg</h2>\n<p>Pod rozwagę gdyby ktoś szukał inspiracji zostawiam że loty z Hamburga bywają znacznie tańsze niż z Amsterdamu - mnie odstraszyła głównie dopłata za bagaż podręczny<sup><a href=\"#user-content-fn-3\" id=\"user-content-fnref-3\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">3</a></sup>. Jest tak blisko do Amsterdamu, że nie ma żadnych nocnych</p>\n<h2 id=\"dortmund\">Dortmund</h2>\n<p>Rozważając kiedyś wyjazd na jeden festiwal gdzie [[Ophidian]] grał, zwróciłem uwagę na to że któraś z tanich linii lotniczy miała tanie połączenie z [[Lotnisko Szymany]].  Niestety, połączenia zostały zawieszone.</p>\n<h2 id=\"eindhoven\">Eindhoven</h2>\n<p>Stamtąd moja podróż się zaczynała, dlatego nie miałem ochoty za bardzo wracać<sup><a href=\"#user-content-fn-4\" id=\"user-content-fnref-4\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">4</a></sup> - zresztą ceny biletów nie były jakieś szczególnie przystępne.</p>\n<h1 id=\"inne-rozwiązania\">Inne rozwiązania</h1>\n<h2 id=\"flixbus-z-berlina\">Flixbus z Berlina</h2>\n<p>Za około 200zł jest 11h powrotu autokarem do Olsztyna.</p>\n<h1 id=\"podsumowanie\">Podsumowanie</h1>\n<p>Zdecydowałem się na powrót przez Monachium. Muzeum BMW, duże parki i bodajże fajne muzea ze sztuką brzmią jak fajny pomysł na dzień.</p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"\" id=\"footnote-label\">Przypisy</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Umykały mi te połączenia z powodu że nie startują z Amsterdam Centraal, tylko jakiegoś innego połączenia. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-2\">\n<p>Też jestem pod wrażeniem jakie niesamowite zniżki mi wchodzą, ale to w większości efekt kupowania porannego biletu z ogromnym wyprzedzeniem chyba. <a href=\"#user-content-fnref-2\" data-footnote-backref=\"\" aria-label=\"Back to reference 2\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-3\">\n<p>Który i tak mam wrażenie że wziąłem na siłę na te kilka dni. <a href=\"#user-content-fnref-3\" data-footnote-backref=\"\" aria-label=\"Back to reference 3\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-4\">\n<p>#ADHD thing, aby wciąż do przodu i wciąż doświadczań nowych bodżców. <a href=\"#user-content-fnref-4\" data-footnote-backref=\"\" aria-label=\"Back to reference 4\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:316,localImagePaths:365,remoteImagePaths:366,frontmatter:367,imagePaths:372},[317,320,324,327,331,334,337,340,343,346,349,352,355,358,361,364],{depth:51,slug:318,text:319},"warunki-brzegowe","Warunki brzegowe",{depth:321,slug:322,text:323},1,"pociągi-nocne","Pociągi nocne",{depth:51,slug:325,text:326},"berlin","Berlin",{depth:328,slug:329,text:330},3,"dlaczego-berlin-to-zła-opcja-na-ten-konkretny-wyjazd","Dlaczego Berlin to zła opcja na ten konkretny wyjazd?",{depth:51,slug:332,text:333},"praga","Praga",{depth:51,slug:335,text:336},"monachium","Monachium",{depth:51,slug:338,text:339},"drezno","Drezno",{depth:51,slug:341,text:342},"wiedeń","Wiedeń",{depth:51,slug:344,text:345},"połączenia-mieszane","Połączenia mieszane",{depth:51,slug:347,text:348},"hamburg","Hamburg",{depth:51,slug:350,text:351},"dortmund","Dortmund",{depth:51,slug:353,text:354},"eindhoven","Eindhoven",{depth:321,slug:356,text:357},"inne-rozwiązania","Inne rozwiązania",{depth:51,slug:359,text:360},"flixbus-z-berlina","Flixbus z Berlina",{depth:321,slug:362,text:363},"podsumowanie","Podsumowanie",{depth:51,slug:52,text:53},[],[],{title:306,draft:20,tags:368,aliases:369,date:370,previewHtml:371},[31,32,198,309],[306],["Date","2024-07-07T00:00:00.000Z"],"<p>Podejmując skądinąd odważną decyzję o wyprawie na  Dominator 2024 i urozmaicając to wypadem do Amsterdamu, pozostaje jeszcze wątek <em>jak wrócić?</em></p>\n<h2>Warunki brzegowe</h2>\n<p>Zakładam że po całym poniedziałku w Amsterdamie zaczyna się wątek powrotu - czyli do dyspozycji jest albo nocny pociąg, albo  nocleg + powrót cały dzień albo dzień przesiadkowy w innej europejskiej stolicy.</p>\n<p>Wszystkie ceny są na dzień dzisiejszy, 07.07.24, planowane trochę do przodu tj. ten poniedziałek to 22.07. Ceny uwzględniają powrót do Olsztyna, gdzie aplikowalne, tam ze żniżką 37% w polskim PKP.</p>\n<h1>Pociągi nocne</h1>\n<p>Z tego co widzę, żeby koszty noclegu połączyć z kosztami transportu są takie opcje:</p>\n<h2>Berlin</h2>\n<p>Na czas tworzenia tego postu #ChatGPT  podpowiedziało mi o istnieniu <a href=\"https://www.europeansleeper.eu/\">European Sleeper</a> , czyli jakimś reboocie pociągów sypialnianych<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup>. Jedyne dostępne na dziś połączenie to komfortowe kuszetki.</p>\n<table>\n<thead>\n<tr>\n<th>Pozycja</th>\n<th>EUR</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Nocny z Amsterdamu do Berlina</td>\n<td>159</td>\n</tr>\n</tbody>\n</table>\n<h3>Dlaczego Berlin to zła opcja <em>na ten konkretny wyjazd</em>?</h3>\n<p>Jakkolwiek dawien dawno chodząc po Warszawie Centralnej z pewnym rozmarzeniem spoglądałem na Berlin-Warszawa-Express zastanawiając się czy kiedykolwiek nim pojadę, to 23.07 zaczyna się remont linii RE1, przez co całość  trochę  mija się z celem - z drugiej strony jest też opcja powrotu przez Szczecin, gdzie busa jest mniej, ale..nie jestem przekonany.</p>\n<h2>Praga</h2>\n<p>W tym samym ES jest też możliwość dotarcia do Pragi, kolejna pozycja to EN z pragi do Warszawy i powrót z Warszawy do Olsztyna<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref aria-describedby=\"footnote-label\">2</a></sup></p>\n<table>\n<thead>\n<tr>\n<th>Pozycja</th>\n<th>EUR</th>\n<th>PLN</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>ES</td>\n<td>179</td>\n<td>~767,33</td>\n</tr>\n<tr>\n<td>EN Praga-Warszawa</td>\n<td></td>\n<td>196,66</td>\n</tr>\n<tr>\n<td>Warszawa-Olsztyn</td>\n<td></td>\n<td>16,36</td>\n</tr>\n<tr>\n<td>Suma</td>\n<td></td>\n<td>980,35</td>\n</tr>\n</tbody>\n</table>\n<h2>Monachium</h2>\n<table>\n<thead>\n<tr>\n<th>Pozycja</th>\n<th>EUR</th>\n<th>PLN</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>EN Amsterdam-Monachium</td>\n<td>105,50</td>\n<td>452,25</td>\n</tr>\n<tr>\n<td>EN Monachium-Warszawa</td>\n<td></td>\n<td>437,56</td>\n</tr>\n<tr>\n<td>Warszawa-Olsztyn</td>\n<td></td>\n<td>16,36</td>\n</tr>\n<tr>\n<td>Suma</td>\n<td></td>\n<td>906,17</td>\n</tr>\n</tbody>\n</table>\n<h2>Drezno</h2>\n<p>Inspiracja z przedziaławki - podróż European Sleeperem do Drezna, stamtąd przesiadka do Zgorzelca, a stamtąd przesiadka we Wrocławiu. Szczerze? Jak spojrzałem na tą propozycję - stwierdziłem że już jestem za stary na takie zabawy.</p>\n<table>\n<thead>\n<tr>\n<th>Pozycja</th>\n<th>EUR</th>\n<th>PLN</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>ES</td>\n<td>179</td>\n<td>767,33</td>\n</tr>\n<tr>\n<td>Drezno - Zgorzelec</td>\n<td>34,90</td>\n<td>149,61</td>\n</tr>\n<tr>\n<td>Zgorzelec - Wrocław</td>\n<td></td>\n<td>20,40</td>\n</tr>\n<tr>\n<td>Wrocław-Olsztyn</td>\n<td></td>\n<td>49,77</td>\n</tr>\n</tbody>\n</table>\n<h2>Wiedeń</h2>\n<p>Akurat te bilety na ten euronight zostały wyprzedane(a szkoda). W każdym razie intercity promo ma na tej trasie praskie ceny - około 200zł.</p>\n<h2>Połączenia mieszane</h2>\n<h2>Hamburg</h2>\n<p>Pod rozwagę gdyby ktoś szukał inspiracji zostawiam że loty z Hamburga bywają znacznie tańsze niż z Amsterdamu - mnie odstraszyła głównie dopłata za bagaż podręczny<sup><a href=\"#user-content-fn-3\" id=\"user-content-fnref-3\" data-footnote-ref aria-describedby=\"footnote-label\">3</a></sup>. Jest tak blisko do Amsterdamu, że nie ma żadnych nocnych</p>\n<h2>Dortmund</h2>\n<p>Rozważając kiedyś wyjazd na jeden festiwal gdzie [[Ophidian]] grał, zwróciłem uwagę na to że któraś z tanich linii lotniczy miała tanie połączenie z [[Lotnisko Szymany]].  Niestety, połączenia zostały zawieszone.</p>\n<h2>Eindhoven</h2>\n<p>Stamtąd moja podróż się zaczynała, dlatego nie miałem ochoty za bardzo wracać<sup><a href=\"#user-content-fn-4\" id=\"user-content-fnref-4\" data-footnote-ref aria-describedby=\"footnote-label\">4</a></sup> - zresztą ceny biletów nie były jakieś szczególnie przystępne.</p>\n<h1>Inne rozwiązania</h1>\n<h2>Flixbus z Berlina</h2>\n<p>Za około 200zł jest 11h powrotu autokarem do Olsztyna.</p>\n<h1>Podsumowanie</h1>\n<p>Zdecydowałem się na powrót przez Monachium. Muzeum BMW, duże parki i bodajże fajne muzea ze sztuką brzmią jak fajny pomysł na dzień.</p>\n",[],"pl/2024/06/udar-a-alkohol",{id:373,data:375,body:381,filePath:382,digest:383,rendered:384},{title:376,date:377,tags:378,draft:20,thread:145},"Udar a alkohol",["Date","2024-06-13T00:00:00.000Z"],[379,143,380],"Alkohol","Praca magisterska","_Żeby mieć trochę contentu, wrzucam stare podejścia do pisania_\n\n Przechodząc przez literaturę do pracy magisterskiej znalazłem jedną, nieoczywistą ciekawostkę: otóż małe[^1] spożycie alkoholu zmniejsza prawdopodobieństwo udaru krwotocznego. Na krwotoczny nie robi różnicy - natomiast picie dużo bądź w ciągach już te prawdopodobieństwo dość mocno zwiększa.\n \n> Light and moderate alcohol consumption was associated with a lower risk of ischemic stroke, whereas high and heavy drinking was associated with an increased risk;\n\n[Źródło.](https://bmcmedicine.biomedcentral.com/articles/10.1186/s12916-016-0721-4) \n\nOczywiście, to nie wyraża mojej opinii wobec alkoholu - tutaj bliżej mi do perspektywy Davida Nutta, autora m.in. [[Narkotyki bez paniki]] która określa alkohol mianem najbardziej szkodliwej używki[^2] - w analizie która nie patrzy tylko na koszty osobowo/zdrowotne, ale patrzy szerzej, uwzględniając też koszty społeczne danej związane z daną substancją.\n\n[^1]: Do 12 gram alkoholu etylowego.\n[^2]: Niestety premiera nowej książki wyparła z SEO googla stare artykuły na ten temat","src/content/thoughts/pl/2024/06/udar-a-alkohol.md","0996e8f5df01c6e8",{html:385,metadata:386},"<p><em>Żeby mieć trochę contentu, wrzucam stare podejścia do pisania</em></p>\n<p>Przechodząc przez literaturę do pracy magisterskiej znalazłem jedną, nieoczywistą ciekawostkę: otóż małe<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup> spożycie alkoholu zmniejsza prawdopodobieństwo udaru krwotocznego. Na krwotoczny nie robi różnicy - natomiast picie dużo bądź w ciągach już te prawdopodobieństwo dość mocno zwiększa.</p>\n<blockquote>\n<p>Light and moderate alcohol consumption was associated with a lower risk of ischemic stroke, whereas high and heavy drinking was associated with an increased risk;</p>\n</blockquote>\n<p><a href=\"https://bmcmedicine.biomedcentral.com/articles/10.1186/s12916-016-0721-4\">Źródło.</a></p>\n<p>Oczywiście, to nie wyraża mojej opinii wobec alkoholu - tutaj bliżej mi do perspektywy Davida Nutta, autora m.in. [[Narkotyki bez paniki]] która określa alkohol mianem najbardziej szkodliwej używki<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">2</a></sup> - w analizie która nie patrzy tylko na koszty osobowo/zdrowotne, ale patrzy szerzej, uwzględniając też koszty społeczne danej związane z daną substancją.</p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"\" id=\"footnote-label\">Przypisy</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Do 12 gram alkoholu etylowego. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-2\">\n<p>Niestety premiera nowej książki wyparła z SEO googla stare artykuły na ten temat <a href=\"#user-content-fnref-2\" data-footnote-backref=\"\" aria-label=\"Back to reference 2\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:387,localImagePaths:389,remoteImagePaths:390,frontmatter:391,imagePaths:395},[388],{depth:51,slug:52,text:53},[],[],{title:376,thread:145,draft:20,tags:392,date:393,previewHtml:394},[379,143,380],["Date","2024-06-13T00:00:00.000Z"],"<p><em>Żeby mieć trochę contentu, wrzucam stare podejścia do pisania</em></p>\n<p>Przechodząc przez literaturę do pracy magisterskiej znalazłem jedną, nieoczywistą ciekawostkę: otóż małe<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup> spożycie alkoholu zmniejsza prawdopodobieństwo udaru krwotocznego. Na krwotoczny nie robi różnicy - natomiast picie dużo bądź w ciągach już te prawdopodobieństwo dość mocno zwiększa.</p>\n<blockquote>\n<p>Light and moderate alcohol consumption was associated with a lower risk of ischemic stroke, whereas high and heavy drinking was associated with an increased risk;</p>\n</blockquote>\n<p><a href=\"https://bmcmedicine.biomedcentral.com/articles/10.1186/s12916-016-0721-4\">Źródło.</a></p>\n<p>Oczywiście, to nie wyraża mojej opinii wobec alkoholu - tutaj bliżej mi do perspektywy Davida Nutta, autora m.in. [[Narkotyki bez paniki]] która określa alkohol mianem najbardziej szkodliwej używki<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref aria-describedby=\"footnote-label\">2</a></sup> - w analizie która nie patrzy tylko na koszty osobowo/zdrowotne, ale patrzy szerzej, uwzględniając też koszty społeczne danej związane z daną substancją.</p>\n",[],"pl/2024/06/malarstwo-a-design-thinking",{id:396,data:398,body:407,filePath:408,digest:409,rendered:410},{title:399,date:400,tags:401,draft:20,thread:406},"Co wspólnego ma malarstwo z design thinking",["Date","2024-07-27T00:00:00.000Z"],[402,403,404,405],"Design Thinking","Malarstwo","Sztuka","Wywiady","design","Jestem jeszcze w czasie gdy dość łapczywie przeglądam zdjęcia z podróży i teraz stwierdziłem że w ramach nasilenia prokrastynacji chcę zobaczyć o co chodzi z książką [*Lie like an artist*](https://www.bispublishers.com/lie-like-an-artist.html) - widziałem ją w przymuzealnych sklepikach zarazem w trzech miastach gdzie miałem okazję zajrzeć do miejsc związanych ze sztuką.\n\nAle przypadkiem trafiłem na artykuł o tym [samym tytule](https://www.roxinekee.com/blog/lie-like-an-artist)\nz którego jeden cytat przykuł moją szczególną uwagę:\n\n> According to our tour guide, McArdle did painstaking truth-finding to produce these two paintings. He conducted countless interviews with veterans, pored through maps and sketches, probably went to these places himself.\n\nMam dość luźne skojarzenie z tym jak Design thinking wygląda obecnie, gdzie wywiady pełnią tę istotną rolę czerpania informacji i tworzenia jeszcze lepszego doświadczenia użytkownika.","src/content/thoughts/pl/2024/06/malarstwo-a-design-thinking.md","3c5c2d0f655740c7",{html:411,metadata:412},"<p>Jestem jeszcze w czasie gdy dość łapczywie przeglądam zdjęcia z podróży i teraz stwierdziłem że w ramach nasilenia prokrastynacji chcę zobaczyć o co chodzi z książką <a href=\"https://www.bispublishers.com/lie-like-an-artist.html\"><em>Lie like an artist</em></a> - widziałem ją w przymuzealnych sklepikach zarazem w trzech miastach gdzie miałem okazję zajrzeć do miejsc związanych ze sztuką.</p>\n<p>Ale przypadkiem trafiłem na artykuł o tym <a href=\"https://www.roxinekee.com/blog/lie-like-an-artist\">samym tytule</a>\nz którego jeden cytat przykuł moją szczególną uwagę:</p>\n<blockquote>\n<p>According to our tour guide, McArdle did painstaking truth-finding to produce these two paintings. He conducted countless interviews with veterans, pored through maps and sketches, probably went to these places himself.</p>\n</blockquote>\n<p>Mam dość luźne skojarzenie z tym jak Design thinking wygląda obecnie, gdzie wywiady pełnią tę istotną rolę czerpania informacji i tworzenia jeszcze lepszego doświadczenia użytkownika.</p>",{headings:413,localImagePaths:414,remoteImagePaths:415,frontmatter:416,imagePaths:419},[],[],[],{title:399,thread:406,draft:20,tags:417,date:418,previewHtml:411},[402,403,404,405],["Date","2024-07-27T00:00:00.000Z"],[],"pl/2024/06/dpd-a-przesylki",{id:420,data:422,body:429,filePath:430,digest:431,rendered:432},{title:423,date:424,tags:425,draft:20},"DPD a przesyłki - jak poprawić jakość niskim kosztem?",["Date","2024-06-13T00:00:00.000Z"],[426,199,427,428],"Typ/insight","Kurierzy","DPD","Nie, żebym samemu miał bardzo nieprzyjemne doświadczenie ze składaniem reklamacji w DPD, dlatego ten protip przeklejam z przyjemnością:\n \n>Ten magiczny \"podpis\", widoczny jako odbiorca w statusie to przepisanie nazwiska z listu na zebrze przy zatwierdzaniu. Fizycznych podpisów kurierzy nie zbierają od czasów covida. Jeśli mirek chciał do rąk odbiorcy, mógł dopłacić DPD za usługę DRW[^1] z pinem, wtedy kurier nie wrzuci takiej paczki za płot, bo będzie musiał wpisać pin od odbiorcy, żeby dobić ją w systemie. Ot cała magia.\n\n[Źródło.](https://wykop.pl/link/7465835/dpd-przerzuca-komputer-przez-plot-niszczy-go-i-bezczelnie-odrzuca-reklamacje/komentarz/124712141/na-dodatek-w-systemie-paczka-widnieje-jako-odebrana-i-podpisana-od-paru-lat-kurierzy-nie-wymagaja-podpisow-po-prostu-paczka-laduje-gdziekolwiek-pod-ty#124712705)\n\n[^1]: Do Rąk Własnych","src/content/thoughts/pl/2024/06/dpd-a-przesylki.md","12eb9ff75ecf8749",{html:433,metadata:434},"<p>Nie, żebym samemu miał bardzo nieprzyjemne doświadczenie ze składaniem reklamacji w DPD, dlatego ten protip przeklejam z przyjemnością:</p>\n<blockquote>\n<p>Ten magiczny “podpis”, widoczny jako odbiorca w statusie to przepisanie nazwiska z listu na zebrze przy zatwierdzaniu. Fizycznych podpisów kurierzy nie zbierają od czasów covida. Jeśli mirek chciał do rąk odbiorcy, mógł dopłacić DPD za usługę DRW<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup> z pinem, wtedy kurier nie wrzuci takiej paczki za płot, bo będzie musiał wpisać pin od odbiorcy, żeby dobić ją w systemie. Ot cała magia.</p>\n</blockquote>\n<p><a href=\"https://wykop.pl/link/7465835/dpd-przerzuca-komputer-przez-plot-niszczy-go-i-bezczelnie-odrzuca-reklamacje/komentarz/124712141/na-dodatek-w-systemie-paczka-widnieje-jako-odebrana-i-podpisana-od-paru-lat-kurierzy-nie-wymagaja-podpisow-po-prostu-paczka-laduje-gdziekolwiek-pod-ty#124712705\">Źródło.</a></p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"\" id=\"footnote-label\">Przypisy</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Do Rąk Własnych <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:435,localImagePaths:437,remoteImagePaths:438,frontmatter:439,imagePaths:446},[436],{depth:51,slug:52,text:53},[],[],{title:423,draft:20,tags:440,aliases:441,date:443,description:444,previewHtml:445},[426,199,427,428],[442],"DPD a przesyłki",["Date","2024-06-13T00:00:00.000Z"],"Jak prostym trikiem sprawić że paczka jednak zobaczy odbiorcę?","<p>Nie, żebym samemu miał bardzo nieprzyjemne doświadczenie ze składaniem reklamacji w DPD, dlatego ten protip przeklejam z przyjemnością:</p>\n<blockquote>\n<p>Ten magiczny “podpis”, widoczny jako odbiorca w statusie to przepisanie nazwiska z listu na zebrze przy zatwierdzaniu. Fizycznych podpisów kurierzy nie zbierają od czasów covida. Jeśli mirek chciał do rąk odbiorcy, mógł dopłacić DPD za usługę DRW<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup> z pinem, wtedy kurier nie wrzuci takiej paczki za płot, bo będzie musiał wpisać pin od odbiorcy, żeby dobić ją w systemie. Ot cała magia.</p>\n</blockquote>\n<p><a href=\"https://wykop.pl/link/7465835/dpd-przerzuca-komputer-przez-plot-niszczy-go-i-bezczelnie-odrzuca-reklamacje/komentarz/124712141/na-dodatek-w-systemie-paczka-widnieje-jako-odebrana-i-podpisana-od-paru-lat-kurierzy-nie-wymagaja-podpisow-po-prostu-paczka-laduje-gdziekolwiek-pod-ty#124712705\">Źródło.</a></p>\n",[],"en/2023/08/github-page-another-repo",{id:447,data:449,body:457,filePath:458,digest:459,rendered:460},{title:450,date:451,tags:452,draft:20},"Implication of deploying github page to another repo",["Date","2023-08-17T13:39:43.000Z"],[453,454,455,456,254],"Astro","Github","CD","Github-actions","_Be aware that it is a n old post. Just reference or an inspiration if someone is lost._\n\n\nYears ago I had a thought to seperate repo with hugo theme and the one with rendered page due to possible use of [utterances](https://utteranc.es/)[^1]. There are my experiences with both approaches:\n\n## deploying page to the same repo\n\n- Astro docs provides a [good starting point](https://docs.astro.build/en/guides/deploy/github/)\n\n## deploying site elsewhere\n\n- There is a a [convinient github-action](https://cpina.github.io/push-to-another-repository-docs/index.html)\n- Can you reuse `withastro/action@v0` to build it? You might, but it is designed for scenario above, this action creates an [artifact](https://docs.github.com/en/actions/using-workflows/storing-workflow-data-as-artifacts) that is consumed by `actions/deploy-pages@v1` action.\n  - tl;dr: there are better ways\n\n### Example of deploying astro blog to github pages\n\n[There is my example](https://github.com/jpalczewski/entuzjazm/blob/6bd91f3a1d60714ab80836c2125b2a654d3a1b63/.github/workflows/deploy.yml) of working github action.\n\nThings worth to note:\n\n- By using actions to install node and pnpm there is huge time savings due to caching.\n- There should be a `.nojekyll` file in blog root - otherwise css is messed up[^2]\n\n[^1]: Is it a good idea? One of tutorials on integrating utterances with astro doesn't have it either. I hope not to see it as a opinion whether this is good option, but someday I will give it a try.\n[^2]: [Source](https://stackoverflow.com/questions/74489844/astro-js-deployment-media-files-not-rendering)","src/content/thoughts/en/2023/08/github-page-another-repo.md","4b5447735bc2fc50",{html:461,metadata:462},"<p><em>Be aware that it is a n old post. Just reference or an inspiration if someone is lost.</em></p>\n<p>Years ago I had a thought to seperate repo with hugo theme and the one with rendered page due to possible use of <a href=\"https://utteranc.es/\">utterances</a><sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup>. There are my experiences with both approaches:</p>\n<h2 id=\"deploying-page-to-the-same-repo\">deploying page to the same repo</h2>\n<ul>\n<li>Astro docs provides a <a href=\"https://docs.astro.build/en/guides/deploy/github/\">good starting point</a></li>\n</ul>\n<h2 id=\"deploying-site-elsewhere\">deploying site elsewhere</h2>\n<ul>\n<li>There is a a <a href=\"https://cpina.github.io/push-to-another-repository-docs/index.html\">convinient github-action</a></li>\n<li>Can you reuse <code>withastro/action@v0</code> to build it? You might, but it is designed for scenario above, this action creates an <a href=\"https://docs.github.com/en/actions/using-workflows/storing-workflow-data-as-artifacts\">artifact</a> that is consumed by <code>actions/deploy-pages@v1</code> action.\n<ul>\n<li>tl;dr: there are better ways</li>\n</ul>\n</li>\n</ul>\n<h3 id=\"example-of-deploying-astro-blog-to-github-pages\">Example of deploying astro blog to github pages</h3>\n<p><a href=\"https://github.com/jpalczewski/entuzjazm/blob/6bd91f3a1d60714ab80836c2125b2a654d3a1b63/.github/workflows/deploy.yml\">There is my example</a> of working github action.</p>\n<p>Things worth to note:</p>\n<ul>\n<li>By using actions to install node and pnpm there is huge time savings due to caching.</li>\n<li>There should be a <code>.nojekyll</code> file in blog root - otherwise css is messed up<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">2</a></sup></li>\n</ul>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"\" id=\"footnote-label\">Footnotes</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Is it a good idea? One of tutorials on integrating utterances with astro doesn’t have it either. I hope not to see it as a opinion whether this is good option, but someday I will give it a try. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-2\">\n<p><a href=\"https://stackoverflow.com/questions/74489844/astro-js-deployment-media-files-not-rendering\">Source</a> <a href=\"#user-content-fnref-2\" data-footnote-backref=\"\" aria-label=\"Back to reference 2\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:463,localImagePaths:475,remoteImagePaths:476,frontmatter:477,imagePaths:482},[464,467,470,473],{depth:51,slug:465,text:466},"deploying-page-to-the-same-repo","deploying page to the same repo",{depth:51,slug:468,text:469},"deploying-site-elsewhere","deploying site elsewhere",{depth:328,slug:471,text:472},"example-of-deploying-astro-blog-to-github-pages","Example of deploying astro blog to github pages",{depth:51,slug:52,text:474},"Footnotes",[],[],{title:450,language:478,date:479,tags:480,previewHtml:481},"en",["Date","2023-08-17T13:39:43.000Z"],[453,454,455,456,254],"<p><em>Be aware that it is a n old post. Just reference or an inspiration if someone is lost.</em></p>\n<p>Years ago I had a thought to seperate repo with hugo theme and the one with rendered page due to possible use of <a href=\"https://utteranc.es/\">utterances</a><sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup>. There are my experiences with both approaches:</p>\n<h2>deploying page to the same repo</h2>\n<ul>\n<li>Astro docs provides a <a href=\"https://docs.astro.build/en/guides/deploy/github/\">good starting point</a></li>\n</ul>\n<h2>deploying site elsewhere</h2>\n<ul>\n<li>There is a a <a href=\"https://cpina.github.io/push-to-another-repository-docs/index.html\">convinient github-action</a></li>\n<li>Can you reuse <code>withastro/action@v0</code> to build it? You might, but it is designed for scenario above, this action creates an <a href=\"https://docs.github.com/en/actions/using-workflows/storing-workflow-data-as-artifacts\">artifact</a> that is consumed by <code>actions/deploy-pages@v1</code> action.\n<ul>\n<li>tl;dr: there are better ways</li>\n</ul>\n</li>\n</ul>\n<h3>Example of deploying astro blog to github pages</h3>\n<p><a href=\"https://github.com/jpalczewski/entuzjazm/blob/6bd91f3a1d60714ab80836c2125b2a654d3a1b63/.github/workflows/deploy.yml\">There is my example</a> of working github action.</p>\n<p>Things worth to note:</p>\n<ul>\n<li>By using actions to install node and pnpm there is huge time savings due to caching.</li>\n<li>There should be a <code>.nojekyll</code> file in blog root - otherwise css is messed up<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref aria-describedby=\"footnote-label\">2</a></sup></li>\n</ul>\n",[],{id:284,data:484,body:493,filePath:494,digest:495,rendered:496},{title:485,date:486,tags:487,draft:20},"How to improve Zotero experience?",["Date","2023-08-29T02:13:17.000Z"],[276,488,489,490,491,492],"Latex","Notion","Obsidian","Sajna","Note-taking","_It's an old note, just for archival purposes. There might be newer alternatives. Also, old blog template used another method of referencing urls, don't have it yet here, so leaving it as-is: [link](\"https://beepb00p.xyz/annotating.html\")_\n\nI have a need to share how much I love [Zotero](https://www.zotero.org/). It was a tool that was a significant part of my academic journey and I had fallen in love while I was writing my B.Sc. thesis[^1], and all coexisting add-ons were indirectly responsible for about 50 references mentioned. I've recently also incorporated Zotero into my workflow alongside another side-project on Notion.\n\nOther remarkable features that Zotero offers:\n\n- Awesome notes on existing PDFs. A bit better than [hypothes.is](https://web.hypothes.is/)[^3] what was my main driver in B.Sc. era for taking notes from PDFs.[^4]\n- Collection mechanism - it's a bit specific approach for zotero and needs time to be used to.\n- Group collections that you can share your findings in teams.[^5]\n\nWhat add-ons were helpful?\n\n## Firefox extension\n\n[Zotero Connector for Firefox](https://www.zotero.org/download/connectors) simplifies the process of adding new database entries. A single click can trigger metadata extraction, and in some cases, even full-text PDF retrieval.[^2]\n\n## Better Bibtex\n\n[Better Bibtex](https://retorque.re/zotero-better-bibtex/) allows exporting yours database in format compatible with Latex.\n\n### Only Latex?\n\nIf you need a place to take notes and mention/link your entries, [Obsidian](https://obsidian.md/) might be a good place to start. There is a great tutorial that was a great inspiration, available [here](vhttps://medium.com/@alexandraphelan/an-academic-workflow-zotero-obsidian-56bf918d51ab).\n\nThere is a newer approach, however, that might work a bit better - [Obsidian Zotero Plugin](https://github.com/PKM-er/obsidian-zotero). Haven't tested yet.\n\n## But what if I want to share my zotero-based entries with friends?\n\nSometime tool just doesn't suit well, and forcing others to use obsidian might be imposing useless cognitive overload, so then Notion comes into play with [notero](https://github.com/dvanoni/notero) extension. Works surprisingly smooth.\n\nTo wrap up, there are more efficient workflows than relying solely on a Word database or gathering references in a single designated file. And they may be integrated with your favorite applications\n\n[^1]: That's the one tag which supposedly is a river and doesn't match to other apps listed.\n[^2]: I was thinking if there may be an extension using other, less legal sources. Yep, they exist.\n[^3]: Zotero has much more colors to highlight text.\n[^4]: While PDF support in Zotero is superior, I was mainly taking notes from websites where hypothesis were better. Look in further sources section for great review of note-taking tools.\n[^5]: Sharing is caring, or something like that.","src/content/thoughts/en/2023/08/zotero-experience.md","21a66278b9451592",{html:497,metadata:498},"<p><em>It’s an old note, just for archival purposes. There might be newer alternatives. Also, old blog template used another method of referencing urls, don’t have it yet here, so leaving it as-is: <a href=\"%22https://beepb00p.xyz/annotating.html%22\">link</a></em></p>\n<p>I have a need to share how much I love <a href=\"https://www.zotero.org/\">Zotero</a>. It was a tool that was a significant part of my academic journey and I had fallen in love while I was writing my B.Sc. thesis<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup>, and all coexisting add-ons were indirectly responsible for about 50 references mentioned. I’ve recently also incorporated Zotero into my workflow alongside another side-project on Notion.</p>\n<p>Other remarkable features that Zotero offers:</p>\n<ul>\n<li>Awesome notes on existing PDFs. A bit better than <a href=\"https://web.hypothes.is/\">hypothes.is</a><sup><a href=\"#user-content-fn-3\" id=\"user-content-fnref-3\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">2</a></sup> what was my main driver in B.Sc. era for taking notes from PDFs.<sup><a href=\"#user-content-fn-4\" id=\"user-content-fnref-4\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">3</a></sup></li>\n<li>Collection mechanism - it’s a bit specific approach for zotero and needs time to be used to.</li>\n<li>Group collections that you can share your findings in teams.<sup><a href=\"#user-content-fn-5\" id=\"user-content-fnref-5\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">4</a></sup></li>\n</ul>\n<p>What add-ons were helpful?</p>\n<h2 id=\"firefox-extension\">Firefox extension</h2>\n<p><a href=\"https://www.zotero.org/download/connectors\">Zotero Connector for Firefox</a> simplifies the process of adding new database entries. A single click can trigger metadata extraction, and in some cases, even full-text PDF retrieval.<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">5</a></sup></p>\n<h2 id=\"better-bibtex\">Better Bibtex</h2>\n<p><a href=\"https://retorque.re/zotero-better-bibtex/\">Better Bibtex</a> allows exporting yours database in format compatible with Latex.</p>\n<h3 id=\"only-latex\">Only Latex?</h3>\n<p>If you need a place to take notes and mention/link your entries, <a href=\"https://obsidian.md/\">Obsidian</a> might be a good place to start. There is a great tutorial that was a great inspiration, available <a href=\"vhttps://medium.com/@alexandraphelan/an-academic-workflow-zotero-obsidian-56bf918d51ab\">here</a>.</p>\n<p>There is a newer approach, however, that might work a bit better - <a href=\"https://github.com/PKM-er/obsidian-zotero\">Obsidian Zotero Plugin</a>. Haven’t tested yet.</p>\n<h2 id=\"but-what-if-i-want-to-share-my-zotero-based-entries-with-friends\">But what if I want to share my zotero-based entries with friends?</h2>\n<p>Sometime tool just doesn’t suit well, and forcing others to use obsidian might be imposing useless cognitive overload, so then Notion comes into play with <a href=\"https://github.com/dvanoni/notero\">notero</a> extension. Works surprisingly smooth.</p>\n<p>To wrap up, there are more efficient workflows than relying solely on a Word database or gathering references in a single designated file. And they may be integrated with your favorite applications</p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"\" id=\"footnote-label\">Footnotes</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>That’s the one tag which supposedly is a river and doesn’t match to other apps listed. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-3\">\n<p>Zotero has much more colors to highlight text. <a href=\"#user-content-fnref-3\" data-footnote-backref=\"\" aria-label=\"Back to reference 2\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-4\">\n<p>While PDF support in Zotero is superior, I was mainly taking notes from websites where hypothesis were better. Look in further sources section for great review of note-taking tools. <a href=\"#user-content-fnref-4\" data-footnote-backref=\"\" aria-label=\"Back to reference 3\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-5\">\n<p>Sharing is caring, or something like that. <a href=\"#user-content-fnref-5\" data-footnote-backref=\"\" aria-label=\"Back to reference 4\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-2\">\n<p>I was thinking if there may be an extension using other, less legal sources. Yep, they exist. <a href=\"#user-content-fnref-2\" data-footnote-backref=\"\" aria-label=\"Back to reference 5\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:499,localImagePaths:513,remoteImagePaths:514,frontmatter:515,imagePaths:520},[500,503,506,509,512],{depth:51,slug:501,text:502},"firefox-extension","Firefox extension",{depth:51,slug:504,text:505},"better-bibtex","Better Bibtex",{depth:328,slug:507,text:508},"only-latex","Only Latex?",{depth:51,slug:510,text:511},"but-what-if-i-want-to-share-my-zotero-based-entries-with-friends","But what if I want to share my zotero-based entries with friends?",{depth:51,slug:52,text:474},[],[],{title:485,description:516,date:517,tags:518,previewHtml:519},"Short review of useful Zotero plugins.",["Date","2023-08-29T02:13:17.000Z"],[276,488,489,490,491,492],"<p><em>It’s an old note, just for archival purposes. There might be newer alternatives. Also, old blog template used another method of referencing urls, don’t have it yet here, so leaving it as-is: <a href=\"%22https://beepb00p.xyz/annotating.html%22\">link</a></em></p>\n<p>I have a need to share how much I love <a href=\"https://www.zotero.org/\">Zotero</a>. It was a tool that was a significant part of my academic journey and I had fallen in love while I was writing my B.Sc. thesis<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup>, and all coexisting add-ons were indirectly responsible for about 50 references mentioned. I’ve recently also incorporated Zotero into my workflow alongside another side-project on Notion.</p>\n<p>Other remarkable features that Zotero offers:</p>\n<ul>\n<li>Awesome notes on existing PDFs. A bit better than <a href=\"https://web.hypothes.is/\">hypothes.is</a><sup><a href=\"#user-content-fn-3\" id=\"user-content-fnref-3\" data-footnote-ref aria-describedby=\"footnote-label\">2</a></sup> what was my main driver in B.Sc. era for taking notes from PDFs.<sup><a href=\"#user-content-fn-4\" id=\"user-content-fnref-4\" data-footnote-ref aria-describedby=\"footnote-label\">3</a></sup></li>\n<li>Collection mechanism - it’s a bit specific approach for zotero and needs time to be used to.</li>\n<li>Group collections that you can share your findings in teams.<sup><a href=\"#user-content-fn-5\" id=\"user-content-fnref-5\" data-footnote-ref aria-describedby=\"footnote-label\">4</a></sup></li>\n</ul>\n<p>What add-ons were helpful?</p>\n<h2>Firefox extension</h2>\n<p><a href=\"https://www.zotero.org/download/connectors\">Zotero Connector for Firefox</a> simplifies the process of adding new database entries. A single click can trigger metadata extraction, and in some cases, even full-text PDF retrieval.<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref aria-describedby=\"footnote-label\">5</a></sup></p>\n<h2>Better Bibtex</h2>\n<p><a href=\"https://retorque.re/zotero-better-bibtex/\">Better Bibtex</a> allows exporting yours database in format compatible with Latex.</p>\n<h3>Only Latex?</h3>\n<p>If you need a place to take notes and mention/link your entries, <a href=\"https://obsidian.md/\">Obsidian</a> might be a good place to start. There is a great tutorial that was a great inspiration, available <a href=\"vhttps://medium.com/@alexandraphelan/an-academic-workflow-zotero-obsidian-56bf918d51ab\">here</a>.</p>\n<p>There is a newer approach, however, that might work a bit better - <a href=\"https://github.com/PKM-er/obsidian-zotero\">Obsidian Zotero Plugin</a>. Haven’t tested yet.</p>\n<h2>But what if I want to share my zotero-based entries with friends?</h2>\n<p>Sometime tool just doesn’t suit well, and forcing others to use obsidian might be imposing useless cognitive overload, so then Notion comes into play with <a href=\"https://github.com/dvanoni/notero\">notero</a> extension. Works surprisingly smooth.</p>\n<p>To wrap up, there are more efficient workflows than relying solely on a Word database or gathering references in a single designated file. And they may be integrated with your favorite applications</p>\n",[],"en/2026/04/rust-docker-cache",{id:521,data:523,body:528,filePath:529,digest:530,rendered:531},{title:524,date:525,tags:526,translationKey:74,draft:20},"Rust, Docker, and the GHA layer caching problem",["Date","2026-04-27T16:30:02.000Z"],[68,69,70,42,71,72,527],"Sideprojects","Lately I've been working on my own vibe-designed todo app rewrite in Rust[^1]. Along the way I started looking for a sensible path to optimizing Docker image builds on GitHub Actions.\n\nOne of the solutions you can easily stumble upon is [`cargo-chef`](https://github.com/lukemathwalker/cargo-chef) — it separates dependency fetching from building the actual code to better cache layers. The problem is it's designed for simpler applications with a single `lib.rs`. In a workspace with more crates it doesn't cache what it should, and every push ends up recompiling everything from scratch.\n\nTwo approaches I tried: buildkit cache dance[^2] — speeds things up a bit, but doesn't cache brilliantly and adds its own time overhead[^3] — and [`swatinem/rust-cache`](https://github.com/swatinem/rust-cache), which works nicely on GHA for binary caching, but deploying Kartoteka as a Docker image on Coolify rules that action out.\n\nResearch turned up `sccache` as worth trying — I made an attempt, but Hetzner S3 is a no-go[^4]. So Cloudflare R2 on the free tier as a potential alternative[^5].\n\nFor now I'm parking at cache dance. Not ruling out going toward my own runner with local cache — just on a slightly bigger server.\n\n[^1]: Kartoteka — somewhere between Todoist, Jira, Amazing Marvin, and Toggl. Classic scope creep.\n[^2]: [Example in the Kartoteka repo.](https://github.com/jpalczewski/kartoteka/blob/a588f99a204ec6c3688f2ae7aafe9ab8cd883559/.github/workflows/docker-build.yml)\n[^3]: In Kartoteka's case there's also the exotic stack — Leptos — which means deploying the server binary together with the built frontend/wasm.\n[^4]: Hetzner S3 bills storage in 1 TB blocks. A bit astronomical for one innocent backup and build artifacts.\n[^5]: Yes, I know — suggesting I go back to Cloudflare when I've spent two weeks rewriting an MCP from a Cloudflare Worker to axum/rmcp specifically to get off the Cloudflare ecosystem, sure.","src/content/thoughts/en/2026/04/rust-docker-cache.md","288306c9ae585380",{html:532,metadata:533},"<p>Lately I’ve been working on my own vibe-designed todo app rewrite in Rust<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup>. Along the way I started looking for a sensible path to optimizing Docker image builds on GitHub Actions.</p>\n<p>One of the solutions you can easily stumble upon is <a href=\"https://github.com/lukemathwalker/cargo-chef\"><code>cargo-chef</code></a> — it separates dependency fetching from building the actual code to better cache layers. The problem is it’s designed for simpler applications with a single <code>lib.rs</code>. In a workspace with more crates it doesn’t cache what it should, and every push ends up recompiling everything from scratch.</p>\n<p>Two approaches I tried: buildkit cache dance<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">2</a></sup> — speeds things up a bit, but doesn’t cache brilliantly and adds its own time overhead<sup><a href=\"#user-content-fn-3\" id=\"user-content-fnref-3\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">3</a></sup> — and <a href=\"https://github.com/swatinem/rust-cache\"><code>swatinem/rust-cache</code></a>, which works nicely on GHA for binary caching, but deploying Kartoteka as a Docker image on Coolify rules that action out.</p>\n<p>Research turned up <code>sccache</code> as worth trying — I made an attempt, but Hetzner S3 is a no-go<sup><a href=\"#user-content-fn-4\" id=\"user-content-fnref-4\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">4</a></sup>. So Cloudflare R2 on the free tier as a potential alternative<sup><a href=\"#user-content-fn-5\" id=\"user-content-fnref-5\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">5</a></sup>.</p>\n<p>For now I’m parking at cache dance. Not ruling out going toward my own runner with local cache — just on a slightly bigger server.</p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"\" id=\"footnote-label\">Footnotes</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Kartoteka — somewhere between Todoist, Jira, Amazing Marvin, and Toggl. Classic scope creep. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-2\">\n<p><a href=\"https://github.com/jpalczewski/kartoteka/blob/a588f99a204ec6c3688f2ae7aafe9ab8cd883559/.github/workflows/docker-build.yml\">Example in the Kartoteka repo.</a> <a href=\"#user-content-fnref-2\" data-footnote-backref=\"\" aria-label=\"Back to reference 2\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-3\">\n<p>In Kartoteka’s case there’s also the exotic stack — Leptos — which means deploying the server binary together with the built frontend/wasm. <a href=\"#user-content-fnref-3\" data-footnote-backref=\"\" aria-label=\"Back to reference 3\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-4\">\n<p>Hetzner S3 bills storage in 1 TB blocks. A bit astronomical for one innocent backup and build artifacts. <a href=\"#user-content-fnref-4\" data-footnote-backref=\"\" aria-label=\"Back to reference 4\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-5\">\n<p>Yes, I know — suggesting I go back to Cloudflare when I’ve spent two weeks rewriting an MCP from a Cloudflare Worker to axum/rmcp specifically to get off the Cloudflare ecosystem, sure. <a href=\"#user-content-fnref-5\" data-footnote-backref=\"\" aria-label=\"Back to reference 5\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:534,localImagePaths:536,remoteImagePaths:537,frontmatter:538,imagePaths:542},[535],{depth:51,slug:52,text:474},[],[],{title:524,date:539,tags:540,draft:20,lang:478,translationKey:74,previewHtml:541},["Date","2026-04-27T16:30:02.000Z"],[68,69,70,42,71,72,527],"<p>Lately I’ve been working on my own vibe-designed todo app rewrite in Rust<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup>. Along the way I started looking for a sensible path to optimizing Docker image builds on GitHub Actions.</p>\n<p>One of the solutions you can easily stumble upon is <a href=\"https://github.com/lukemathwalker/cargo-chef\"><code>cargo-chef</code></a> — it separates dependency fetching from building the actual code to better cache layers. The problem is it’s designed for simpler applications with a single <code>lib.rs</code>. In a workspace with more crates it doesn’t cache what it should, and every push ends up recompiling everything from scratch.</p>\n<p>Two approaches I tried: buildkit cache dance<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref aria-describedby=\"footnote-label\">2</a></sup> — speeds things up a bit, but doesn’t cache brilliantly and adds its own time overhead<sup><a href=\"#user-content-fn-3\" id=\"user-content-fnref-3\" data-footnote-ref aria-describedby=\"footnote-label\">3</a></sup> — and <a href=\"https://github.com/swatinem/rust-cache\"><code>swatinem/rust-cache</code></a>, which works nicely on GHA for binary caching, but deploying Kartoteka as a Docker image on Coolify rules that action out.</p>\n<p>Research turned up <code>sccache</code> as worth trying — I made an attempt, but Hetzner S3 is a no-go<sup><a href=\"#user-content-fn-4\" id=\"user-content-fnref-4\" data-footnote-ref aria-describedby=\"footnote-label\">4</a></sup>. So Cloudflare R2 on the free tier as a potential alternative<sup><a href=\"#user-content-fn-5\" id=\"user-content-fnref-5\" data-footnote-ref aria-describedby=\"footnote-label\">5</a></sup>.</p>\n<p>For now I’m parking at cache dance. Not ruling out going toward my own runner with local cache — just on a slightly bigger server.</p>\n",[],"en/2026/04/looking-for-aaaaa-rave",{id:543,data:545,body:550,filePath:551,assetImports:552,digest:554,rendered:555},{title:546,date:547,tags:548,translationKey:549,draft:24},"Looking for AAAAA Rave",["Date","2026-04-27T00:00:00.000Z"],[],"aaaaa-rave-szukam-2026-04","# Looking for AAAAA Rave\n\n![Resident Advisor](@assets/images/resident-advisor.png \"Search results on Resident Advisor for Poland, April 2026\")\n\nHello world.","src/content/thoughts/en/2026/04/looking-for-aaaaa-rave.md",[553],"../../../../../assets/images/resident-advisor.png","92280d9efbda4164",{html:556,metadata:557},"<h1 id=\"looking-for-aaaaa-rave\">Looking for AAAAA Rave</h1>\n<p></p><figure class=\"post-figure\"><img __ASTRO_IMAGE_=\"{&#x22;src&#x22;:&#x22;../../../../../assets/images/resident-advisor.png&#x22;,&#x22;alt&#x22;:&#x22;Resident Advisor&#x22;,&#x22;index&#x22;:0}\"><figcaption>Search results on Resident Advisor for Poland, April 2026</figcaption></figure><p></p>\n<p>Hello world.</p>",{headings:558,localImagePaths:561,remoteImagePaths:562,frontmatter:563,imagePaths:567},[559],{depth:321,slug:560,text:546},"looking-for-aaaaa-rave",[553],[],{title:546,date:564,tags:565,translationKey:549,draft:24,lang:478,previewHtml:566},["Date","2026-04-27T00:00:00.000Z"],[],"<h1>Looking for AAAAA Rave</h1>\n<p><figure class=\"post-figure\"><img src=\"/__preview_asset__/assets/images/resident-advisor.png\" alt=\"Resident Advisor\"><figcaption>Search results on Resident Advisor for Poland, April 2026</figcaption></figure></p>\n<p>Hello world.</p>",[553],"en/2025/11/articles-used-in-creating-this-blog",{id:568,data:570,body:575,filePath:576,digest:577,rendered:578},{title:571,date:572,tags:573,translationKey:122,draft:24},"Articles used in creating this blog",["Date","2025-11-13T00:00:00.000Z"],[574],"Web-development","Just to point out sources that saved me a bit of ~~googling~~ tokens:\n- https://www.andrewhoog.com/posts/how-to-annotate-blog-posts-with-footnotes-in-astro/ [^1]\n\n\n[^1]: It works!","src/content/thoughts/en/2025/11/articles-used-in-creating-this-blog.md","65480184887820e6",{html:579,metadata:580},"<p>Just to point out sources that saved me a bit of <del>googling</del> tokens:</p>\n<ul>\n<li><a href=\"https://www.andrewhoog.com/posts/how-to-annotate-blog-posts-with-footnotes-in-astro/\">https://www.andrewhoog.com/posts/how-to-annotate-blog-posts-with-footnotes-in-astro/</a> <sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup></li>\n</ul>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"\" id=\"footnote-label\">Footnotes</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>It works! <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:581,localImagePaths:583,remoteImagePaths:584,frontmatter:585,imagePaths:590},[582],{depth:51,slug:52,text:474},[],[],{title:571,description:586,date:587,tags:588,draft:24,lang:478,translationKey:122,previewHtml:589},"A new post about web-development",["Date","2025-11-13T00:00:00.000Z"],[574],"<p>Just to point out sources that saved me a bit of <del>googling</del> tokens:</p>\n<ul>\n<li><a href=\"https://www.andrewhoog.com/posts/how-to-annotate-blog-posts-with-footnotes-in-astro/\">https://www.andrewhoog.com/posts/how-to-annotate-blog-posts-with-footnotes-in-astro/</a> <sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup></li>\n</ul>\n",[]];

